import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface ERPRecord {
  productCode: string;
  brand: string;
  colorName: string;
}

export interface ExtractedInfo {
  fileName: string;
  fullPath: string;
  brandHint: string;
  productCode: string;
  colorCode: string;
  tokens: string[];
}

export interface MatchResult extends ExtractedInfo {
  isMatch: boolean;
  isFuzzy: boolean;
  erpBrand?: string;
  erpColorName?: string;
  fuzzyMatchCode?: string;
  status: 'SUCCESS' | 'FUZZY' | 'FAILURE';
}

export enum FileStatus {
  IDLE = 'IDLE',
  PROCESSING = 'PROCESSING',
  COMPLETE = 'COMPLETE',
  ERROR = 'ERROR'
}

export const COLOR_MAPPINGS: Record<string, string> = {
  'BK': 'BLK',
  'WNV': 'NVY',
  'WH': 'WHT',
  'BL': 'BLU',
  'RD': 'RED',
  'GR': 'GRN'
};

export const BRANDS_WITH_DASH_RULE = ['SKECHERS', 'HOKA', 'SAUCONY'];

export const DELIMITERS = /[_.\-\s]+/;

/**
 * Calculates the Levenshtein distance between two strings.
 */
export const getLevenshteinDistance = (a: string, b: string): number => {
  const matrix: number[][] = [];

  for (let i = 0; i <= b.length; i++) {
    matrix[i] = [i];
  }

  for (let j = 0; j <= a.length; j++) {
    matrix[0][j] = j;
  }

  for (let i = 1; i <= b.length; i++) {
    for (let j = 1; j <= a.length; j++) {
      if (b.charAt(i - 1) === a.charAt(j - 1)) {
        matrix[i][j] = matrix[i - 1][j - 1];
      } else {
        matrix[i][j] = Math.min(
          matrix[i - 1][j - 1] + 1, // substitution
          matrix[i][j - 1] + 1,     // insertion
          matrix[i - 1][j] + 1      // deletion
        );
      }
    }
  }

  return matrix[b.length][a.length];
};

/**
 * Finds the best match in a list of codes based on Levenshtein distance.
 */
export const findBestFuzzyMatch = (
  target: string,
  candidates: string[],
  threshold: number = 2
): { code: string; distance: number } | null => {
  let bestMatch = null;
  let minDistance = Infinity;

  for (const candidate of candidates) {
    const distance = getLevenshteinDistance(target.toUpperCase(), candidate.toUpperCase());
    if (distance < minDistance) {
      minDistance = distance;
      bestMatch = candidate;
    }
  }

  if (bestMatch && minDistance <= threshold) {
    return { code: bestMatch, distance: minDistance };
  }

  return null;
};

import { BRANDS_WITH_DASH_RULE, DELIMITERS, COLOR_MAPPINGS } from '../constants';
import { ExtractedInfo } from '../types';

export const normalizeColor = (code: string): string => {
  const upper = code.toUpperCase();
  return COLOR_MAPPINGS[upper] || upper;
};

export const parseFilename = (file: File): ExtractedInfo => {
  // Use webkitRelativePath if available (for folder selection), else just name
  const fullPath = file.webkitRelativePath || file.name;
  const fileNameWithExt = file.name;
  const nameNoExt = fileNameWithExt.substring(0, fileNameWithExt.lastIndexOf('.')) || fileNameWithExt;

  // Extract Brand Hint from path: Imagery - [BRAND]
  const brandMatch = fullPath.match(/Imagery - ([^\/\\]+)/i);
  const brandHint = brandMatch ? brandMatch[1].toUpperCase() : "UNKNOWN";

  // Tokenize
  const tokens = nameNoExt.split(DELIMITERS).filter(t => t.length > 0);

  let prodCode = "";
  let colorCode = "";

  if (BRANDS_WITH_DASH_RULE.includes(brandHint)) {
    if (tokens.length >= 2) {
      prodCode = `${tokens[0]}-${tokens[1]}`;
      colorCode = tokens[1];
    } else {
      prodCode = tokens[0] || "";
    }
  } else if (tokens.length >= 2 && /^\d{3}$/.test(tokens[1])) {
    // Nike/Asics style (Token1 is 3 digits)
    prodCode = `${tokens[0]}-${tokens[1]}`;
    colorCode = tokens[1];
  } else {
    prodCode = tokens[0] || "";
    // Simple heuristic for color: look for 3-char tokens later in the list
    const potentialColor = tokens.find((t, idx) => idx > 0 && t.length === 3);
    colorCode = potentialColor || "";
  }

  return {
    fileName: fileNameWithExt,
    fullPath,
    brandHint,
    productCode: prodCode,
    colorCode: normalizeColor(colorCode),
    tokens
  };
};

export const parseCSV = (csvText: string): any[] => {
  const lines = csvText.split(/\r?\n/);
  if (lines.length < 2) return [];

  const headers = lines[0].split(',').map(h => h.trim().toLowerCase());

  return lines.slice(1).filter(line => line.trim()).map(line => {
    const values = line.split(',');
    const obj: any = {};
    headers.forEach((header, i) => {
      obj[header] = values[i] ? values[i].trim() : "";
    });
    return obj;
  });
};

import React, { useRef } from 'react';

interface FileUploadZoneProps {
  onFilesSelected: (files: File[]) => void;
  label: string;
  accept?: string;
  isFolder?: boolean;
}

const FileUploadZone: React.FC<FileUploadZoneProps> = ({ onFilesSelected, label, accept, isFolder }) => {
  const inputRef = useRef<HTMLInputElement>(null);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      onFilesSelected(Array.from(e.target.files));
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    if (e.dataTransfer.files) {
      onFilesSelected(Array.from(e.dataTransfer.files));
    }
  };

  return (
    <div 
      onDragOver={handleDragOver}
      onDrop={handleDrop}
      onClick={() => inputRef.current?.click()}
      className="border-2 border-dashed border-slate-300 rounded-xl p-8 text-center hover:border-indigo-500 hover:bg-indigo-50 transition-all cursor-pointer group"
    >
      <input 
        type="file" 
        className="hidden" 
        ref={inputRef}
        onChange={handleChange}
        accept={accept}
        {...(isFolder ? { webkitdirectory: "true", directory: "true" } as any : {})}
      />
      <div className="flex flex-col items-center gap-3">
        <div className="p-3 bg-indigo-100 rounded-full text-indigo-600 group-hover:scale-110 transition-transform">
          {isFolder ? (
            <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 7v10a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-6l-2-2H5a2 2 0 00-2 2z" />
            </svg>
          ) : (
            <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
            </svg>
          )}
        </div>
        <p className="text-slate-600 font-medium">{label}</p>
        <p className="text-slate-400 text-sm">Or drag and drop files here</p>
      </div>
    </div>
  );
};

export default FileUploadZone;

import React from 'react';
import { MatchResult } from '../types';

interface ResultsTableProps {
  results: MatchResult[];
}

const ResultsTable: React.FC<ResultsTableProps> = ({ results }) => {
  return (
    <div className="overflow-x-auto rounded-xl border border-slate-200 shadow-sm bg-white">
      <table className="w-full text-left text-sm">
        <thead className="bg-slate-50 text-slate-500 uppercase font-semibold">
          <tr>
            <th className="px-6 py-4">Original File</th>
            <th className="px-6 py-4">Extracted Code</th>
            <th className="px-6 py-4">Match Status</th>
            <th className="px-6 py-4">Brand (ERP)</th>
            <th className="px-6 py-4">Color Name</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-slate-100">
          {results.map((res, idx) => (
            <tr key={idx} className="hover:bg-slate-50 transition-colors">
              <td className="px-6 py-4 font-mono text-xs text-slate-600">{res.fileName}</td>
              <td className="px-6 py-4 font-semibold text-slate-800">
                {res.productCode}
                {res.isFuzzy && (
                  <span className="block text-[10px] text-orange-500 font-normal">
                    Fuzzy Match: {res.fuzzyMatchCode}
                  </span>
                )}
              </td>
              <td className="px-6 py-4">
                <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                  res.status === 'SUCCESS' ? 'bg-green-100 text-green-700' :
                  res.status === 'FUZZY' ? 'bg-orange-100 text-orange-700' :
                  'bg-red-100 text-red-700'
                }`}>
                  {res.status}
                </span>
              </td>
              <td className="px-6 py-4 text-slate-600">{res.erpBrand || '—'}</td>
              <td className="px-6 py-4 text-slate-600">{res.erpColorName || '—'}</td>
            </tr>
          ))}
          {results.length === 0 && (
            <tr>
              <td colSpan={5} className="px-6 py-12 text-center text-slate-400 italic">
                No files processed yet.
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
};

export default ResultsTable;

import React, { useState, useCallback } from 'react';
import FileUploadZone from './components/FileUploadZone';
import ResultsTable from './components/ResultsTable';
import { ERPRecord, MatchResult, FileStatus } from './types';
import { parseFilename, parseCSV } from './utils/parser';
import { findBestFuzzyMatch } from './utils/fuzzy';

const App: React.FC = () => {
  const [erpData, setErpData] = useState<ERPRecord[]>([]);
  const [results, setResults] = useState<MatchResult[]>([]);
  const [status, setStatus] = useState<FileStatus>(FileStatus.IDLE);
  const [erpFileName, setErpFileName] = useState<string>('');

  const handleERPUpload = useCallback((files: File[]) => {
    if (files.length === 0) return;
    const file = files[0];
    setErpFileName(file.name);
    const reader = new FileReader();
    reader.onload = (e) => {
      const text = e.target?.result as string;
      const rawData = parseCSV(text);

      // Standardize data from CSV
      // Assuming headers might be: ProductCode, Brand, ColorName, etc.
      const sanitizedData: ERPRecord[] = rawData.map(row => ({
        productCode: String(row.productcode || row['product code'] || row.sku || '').toUpperCase(),
        brand: String(row.brand || '').toUpperCase(),
        colorName: String(row.colorname || row['color name'] || row.color || '').trim()
      }));

      setErpData(sanitizedData);
    };
    reader.readAsText(file);
  }, []);

  const handleFileProcessing = useCallback((files: File[]) => {
    if (files.length === 0) return;
    setStatus(FileStatus.PROCESSING);

    // Slight timeout to let UI update before heavy lifting
    setTimeout(() => {
      const extracted = files.filter(f => f.type.startsWith('image/')).map(file => parseFilename(file));
      const erpCodes = erpData.map(d => d.productCode);

      const matchedResults: MatchResult[] = extracted.map(info => {
        const directMatch = erpData.find(d => d.productCode.toUpperCase() === info.productCode.toUpperCase());

        if (directMatch) {
          return {
            ...info,
            isMatch: true,
            isFuzzy: false,
            erpBrand: directMatch.brand,
            erpColorName: directMatch.colorName,
            status: 'SUCCESS' as const
          };
        }

        // Fuzzy Match
        const fuzzy = findBestFuzzyMatch(info.productCode, erpCodes, 2);
        if (fuzzy) {
          const fuzzyRecord = erpData.find(d => d.productCode === fuzzy.code);
          return {
            ...info,
            isMatch: true,
            isFuzzy: true,
            fuzzyMatchCode: fuzzy.code,
            erpBrand: fuzzyRecord?.brand,
            erpColorName: fuzzyRecord?.colorName,
            status: 'FUZZY' as const
          };
        }

        return {
          ...info,
          isMatch: false,
          isFuzzy: false,
          status: 'FAILURE' as const
        };
      });

      setResults(matchedResults);
      setStatus(FileStatus.COMPLETE);
    }, 100);
  }, [erpData]);

  const stats = {
    total: results.length,
    success: results.filter(r => r.status === 'SUCCESS').length,
    fuzzy: results.filter(r => r.status === 'FUZZY').length,
    failure: results.filter(r => r.status === 'FAILURE').length
  };

  return (
    <div className="min-h-screen bg-slate-50 p-4 md:p-10 font-sans">
      <div className="max-w-6xl mx-auto space-y-8">
        {/* Header */}
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h1 className="text-3xl font-bold text-slate-900 tracking-tight">ERP Filename Validator</h1>
            <p className="text-slate-500 mt-1">Normalize image filenames and validate against master product data.</p>
          </div>
          <div className="flex items-center gap-3">
            <div className={`h-3 w-3 rounded-full ${status === FileStatus.PROCESSING ? 'bg-indigo-500 animate-pulse' : 'bg-green-500'}`} />
            <span className="text-sm font-semibold text-slate-700">{status}</span>
          </div>
        </header>

        {/* Setup Section */}
        <section className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 space-y-4">
            <div className="flex items-center gap-2 mb-2">
              <div className="bg-slate-100 p-2 rounded-lg">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-slate-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                </svg>
              </div>
              <h2 className="font-bold text-lg text-slate-800">1. Source of Truth (ERP)</h2>
            </div>
            <FileUploadZone 
              label="Select ERP CSV Table" 
              onFilesSelected={handleERPUpload} 
              accept=".csv"
            />
            {erpFileName && (
              <div className="flex items-center gap-2 text-sm text-green-600 bg-green-50 p-3 rounded-lg border border-green-100">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                </svg>
                <span>Loaded: {erpFileName} ({erpData.length} records)</span>
              </div>
            )}
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 space-y-4">
            <div className="flex items-center gap-2 mb-2">
              <div className="bg-slate-100 p-2 rounded-lg">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-slate-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                </svg>
              </div>
              <h2 className="font-bold text-lg text-slate-800">2. Upload Imagery</h2>
            </div>
            <FileUploadZone 
              label="Select Folder or Drag Images" 
              onFilesSelected={handleFileProcessing} 
              isFolder={true}
              accept="image/*"
            />
            {erpData.length === 0 && (
              <p className="text-xs text-amber-600 bg-amber-50 p-3 rounded-lg border border-amber-100">
                ⚠️ Upload an ERP table first to enable validation.
              </p>
            )}
          </div>
        </section>

        {/* Dashboard Stats */}
        {results.length > 0 && (
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            {[
              { label: 'Total Files', value: stats.total, color: 'indigo' },
              { label: 'Exact Matches', value: stats.success, color: 'green' },
              { label: 'Fuzzy Matches', value: stats.fuzzy, color: 'orange' },
              { label: 'Flagged / Miss', value: stats.failure, color: 'red' }
            ].map(stat => (
              <div key={stat.label} className={`bg-${stat.color}-50 p-4 rounded-xl border border-${stat.color}-100`}>
                <p className={`text-${stat.color}-600 text-xs font-bold uppercase`}>{stat.label}</p>
                <p className={`text-2xl font-black text-${stat.color}-900`}>{stat.value}</p>
              </div>
            ))}
          </div>
        )}

        {/* Results */}
        <main className="space-y-4">
          <div className="flex items-center justify-between">
            <h3 className="text-xl font-bold text-slate-800">Processing Results</h3>
            {results.length > 0 && (
              <button 
                onClick={() => setResults([])}
                className="text-sm text-slate-500 hover:text-red-600 font-medium transition-colors"
              >
                Clear Results
              </button>
            )}
          </div>
          <ResultsTable results={results} />
        </main>
      </div>
    </div>
  );
};

export default App;

export const COLOR_MAPPINGS: Record<string, string> = {
  'BK': 'BLK',
  'WNV': 'NVY',
  'WH': 'WHT',
  'BL': 'BLU',
  'RD': 'RED',
  'GR': 'GRN',
  'WT': 'WHT',
  'OR': 'ORG',
  'GY': 'GRY',
  'PK': 'PNK'
};

export const BRANDS_WITH_DASH_RULE = ['SKECHERS', 'HOKA', 'SAUCONY'];

// Words that are likely descriptive or brand names and NOT part of a product code
export const NOISE_WORDS = new Set([
  'NIKE', 'ADIDAS', 'SKECHERS', 'ASICS', 'HOKA', 'SAUCONY',
  'AURORA', 'AIR', 'MAX', 'VAPOR', 'FLYKNIT', 'PLUS', 'IMAGERY',
  'SAMPLE', 'FINAL', 'EDIT', 'WEB', 'HIGH', 'LOW', 'RETRO'
]);

export const DELIMITERS = /[_.\-\s]+/;

import { BRANDS_WITH_DASH_RULE, DELIMITERS, COLOR_MAPPINGS, NOISE_WORDS } from '../constants';
import { ExtractedInfo } from '../types';

export const normalizeColor = (code: string): string => {
  const upper = code.toUpperCase();
  return COLOR_MAPPINGS[upper] || upper;
};

/**
 * Checks if a string is likely a color code (3 chars, or in our mapping)
 */
const isLikelyColor = (token: string): boolean => {
  const upper = token.toUpperCase();
  return (upper.length === 3) || !!COLOR_MAPPINGS[upper];
};

/**
 * Checks if a token is a "heavy" alphanumeric code (contains digits)
 */
const isHeavyToken = (token: string): boolean => {
  return /\d/.test(token);
};

export const parseFilename = (file: File): ExtractedInfo => {
  const fullPath = file.webkitRelativePath || file.name;
  const fileNameWithExt = file.name;
  const nameNoExt = fileNameWithExt.substring(0, fileNameWithExt.lastIndexOf('.')) || fileNameWithExt;

  // 1. Extract Brand Hint from path
  const brandMatch = fullPath.match(/Imagery - ([^\/\\]+)/i);
  const brandHint = brandMatch ? brandMatch[1].toUpperCase() : "UNKNOWN";

  // 2. Tokenize and filter out "Noise"
  const allTokens = nameNoExt.split(DELIMITERS).filter(t => t.length > 0);

  // Filtered tokens for code extraction: Remove brand name and common noise words
  const validTokens = allTokens.filter(t => {
    const upper = t.toUpperCase();
    return !NOISE_WORDS.has(upper) && upper !== brandHint;
  });

  let prodCode = "";
  let colorCode = "";

  // 3. Proactive Color Extraction (Look for color patterns in any token)
  const colorCandidate = allTokens.find(t => isLikelyColor(t) && !NOISE_WORDS.has(t.toUpperCase()));
  if (colorCandidate) {
    colorCode = normalizeColor(colorCandidate);
  }

  // 4. Heuristic Product Code Construction
  if (BRANDS_WITH_DASH_RULE.includes(brandHint)) {
    // Skechers Rule: Token1-Token2 (if available)
    if (validTokens.length >= 2) {
      prodCode = `${validTokens[0]}-${validTokens[1]}`;
    } else {
      prodCode = validTokens[0] || "";
    }
  } else {
    // Nike/Asics/General Rule
    // Look for first heavy token
    const firstHeavyIdx = validTokens.findIndex(isHeavyToken);

    if (firstHeavyIdx !== -1) {
      const token1 = validTokens[firstHeavyIdx];
      const token2 = validTokens[firstHeavyIdx + 1];

      // If token2 is exactly 3 digits (common color/style suffix for Nike/Asics)
      if (token2 && /^\d{3}$/.test(token2)) {
        prodCode = `${token1}-${token2}`;
        // If we hadn't found a color yet, this 3-digit suffix is a strong candidate
        if (!colorCode) colorCode = token2;
      } else {
        prodCode = token1;
      }
    } else {
      // Fallback to first non-noise token
      prodCode = validTokens[0] || "";
    }
  }

  return {
    fileName: fileNameWithExt,
    fullPath,
    brandHint,
    productCode: prodCode,
    colorCode,
    tokens: allTokens
  };
};

export const parseCSV = (csvText: string): any[] => {
  const lines = csvText.split(/\r?\n/);
  if (lines.length < 2) return [];

  const headers = lines[0].split(',').map(h => h.trim().toLowerCase());

  return lines.slice(1).filter(line => line.trim()).map(line => {
    // Handle basic CSV splitting (simple, no complex quoting handled here)
    const values = line.split(',');
    const obj: any = {};
    headers.forEach((header, i) => {
      obj[header] = values[i] ? values[i].trim() : "";
    });
    return obj;
  });
};

import React from 'react';
import { MatchResult } from '../types';

interface ResultsTableProps {
  results: MatchResult[];
}

const ResultsTable: React.FC<ResultsTableProps> = ({ results }) => {
  return (
    <div className="overflow-x-auto rounded-xl border border-slate-200 shadow-sm bg-white">
      <table className="w-full text-left text-sm">
        <thead className="bg-slate-50 text-slate-500 uppercase font-semibold">
          <tr>
            <th className="px-6 py-4">Original File</th>
            <th className="px-6 py-4">Extracted Code</th>
            <th className="px-6 py-4">Ext. Color</th>
            <th className="px-6 py-4">Match Status</th>
            <th className="px-6 py-4">ERP Brand</th>
            <th className="px-6 py-4">ERP Color Description</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-slate-100">
          {results.map((res, idx) => (
            <tr key={idx} className="hover:bg-slate-50 transition-colors">
              <td className="px-6 py-4 font-mono text-xs text-slate-600">
                <span className="block truncate max-w-[200px]" title={res.fileName}>
                  {res.fileName}
                </span>
              </td>
