  const brandMatch = path.match(/Imagery - ([^\/\\]+)/i);
  const brandHint = brandMatch ? brandMatch[1].toUpperCase() : "UNKNOWN";

  const allTokens = nameNoExt.split(DELIMITERS).filter(t => t.length > 0);

  // Filter out brand hints and noise words, but preserve segments that look like codes
  const validTokens = allTokens.filter(t => {
    const upper = t.toUpperCase();
    return upper !== brandHint && !isDescriptiveWord(t);
  });

  const candidates: string[] = [];
  let colorCode = "";

  // 1. Progressive Fallback Generation (Short -> Medium -> Long)
  if (validTokens.length > 0) {
    const t1 = validTokens[0].toUpperCase();
    candidates.push(t1); // Try base first (e.g., MR7441A)

    if (validTokens.length > 1) {
      const t2 = validTokens[1].toUpperCase();
      candidates.push(`${t1}-${t2}`); // Try base + 2nd (e.g., MR7441A-BLK)

      if (validTokens.length > 2) {
        const t3 = validTokens[2].toUpperCase();
        candidates.push(`${t1}-${t2}-${t3}`); // Try base + 2nd + 3rd (e.g., MR7441A-BLK-SRF)
      }
    }
  }

  // 2. Proactive Color Extraction for UI display
  const colorCandidate = allTokens.find(t => isLikelyColor(t));
  if (colorCandidate) {
    colorCode = normalizeColor(colorCandidate);
  }

  return {
    fileName: inputName,
    fullPath: path,
    brandHint,
    candidateCodes: candidates,
    productCode: candidates[0] || "", // Use base as default display
    colorCode: colorCode.toUpperCase(),
    tokens: allTokens
  };
};

export const parseCSV = (csvText: string): any[] => {
  const lines = csvText.split(/\r?\n/);
  if (lines.length < 2) return [];

  const delimiter = lines[0].includes('\t') ? '\t' : ',';
  const headers = lines[0].split(delimiter).map(h => h.trim().toLowerCase());

  return lines.slice(1).filter(line => line.trim()).map(line => {
    const values = line.split(delimiter);
    const obj: any = {};
    headers.forEach((header, i) => {
      obj[header] = values[i] ? values[i].trim() : "";
    });
    return obj;
  });
};

import React, { useState, useCallback } from 'react';
import FileUploadZone from './components/FileUploadZone';
import ResultsTable from './components/ResultsTable';
import { ERPRecord, MatchResult, FileStatus } from './types';
import { parseFilename, parseCSV } from './utils/parser';
import { findBestFuzzyMatch } from './utils/fuzzy';

const App: React.FC = () => {
  const [erpData, setErpData] = useState<ERPRecord[]>([]);
  const [results, setResults] = useState<MatchResult[]>([]);
  const [status, setStatus] = useState<FileStatus>(FileStatus.IDLE);
  const [erpFileName, setErpFileName] = useState<string>('');

  const handleERPUpload = useCallback((files: File[]) => {
    if (files.length === 0) return;
    const file = files[0];
    setErpFileName(file.name);
    const reader = new FileReader();
    reader.onload = (e) => {
      const text = e.target?.result as string;
      const rawData = parseCSV(text);
      const sanitizedData: ERPRecord[] = rawData.map(row => ({
        productCode: String(row.productcode || row['product code'] || row.sku || '').toUpperCase().trim(),
        brand: String(row.brand || '').toUpperCase().trim(),
        colorName: String(row.colorname || row['color name'] || row.color || '').trim()
      })).filter(r => r.productCode);
      setErpData(sanitizedData);
    };
    reader.readAsText(file);
  }, []);

  const processEntries = useCallback((entries: {name: string, path: string}[]) => {
    setStatus(FileStatus.PROCESSING);

    setTimeout(() => {
      const extracted = entries.map(entry => parseFilename(entry.name, entry.path));
      const erpCodes = erpData.map(d => d.productCode);

      const matchedResults: MatchResult[] = extracted.map(info => {
        const attempts = info.candidateCodes;

        // 1. Stage-based Direct Matching (3-stage fallback)
        let directMatch: ERPRecord | undefined = undefined;
        let matchedAtStage: string | undefined = undefined;

        for (const candidate of attempts) {
          const found = erpData.find(d => d.productCode === candidate);
          if (found) {
            directMatch = found;
            matchedAtStage = candidate;
            break; // Stop at first successful match in the hierarchy
          }
        }

        if (directMatch && matchedAtStage) {
          return {
            ...info,
            productCode: matchedAtStage,
            attempts,
            isMatch: true,
            isFuzzy: false,
            erpBrand: directMatch.brand,
            erpColorName: directMatch.colorName,
            status: 'SUCCESS' as const,
            reason: `Found exact match for: ${matchedAtStage}`
          };
        }

        // 2. Fuzzy Match across all candidates
        let bestFuzzy: { code: string; distance: number; source: string } | null = null;
        for (const candidate of attempts) {
          const fuzzy = findBestFuzzyMatch(candidate, erpCodes, 2);
          if (fuzzy && (!bestFuzzy || fuzzy.distance < bestFuzzy.distance)) {
            bestFuzzy = { ...fuzzy, source: candidate };
          }
        }

        if (bestFuzzy) {
          const fuzzyRecord = erpData.find(d => d.productCode === bestFuzzy!.code);
          return {
            ...info,
            attempts,
            isMatch: true,
            isFuzzy: true,
            fuzzyMatchCode: bestFuzzy.code,
            erpBrand: fuzzyRecord?.brand,
            erpColorName: fuzzyRecord?.colorName,
            status: 'FUZZY' as const,
            reason: `Fuzzy matched "${bestFuzzy.source}" to "${bestFuzzy.code}" (Dist: ${bestFuzzy.distance})`
          };
        }

        // 3. Failure
        return {
          ...info,
          attempts,
          isMatch: false,
          isFuzzy: false,
          status: 'FAILURE' as const,
          reason: `No records found in ERP for any candidates: ${attempts.join(', ')}`
        };
      });

      setResults(matchedResults);
      setStatus(FileStatus.COMPLETE);
    }, 100);
  }, [erpData]);

  const handleFileProcessing = useCallback((files: File[]) => {
    if (files.length === 0) return;

    const csvFile = files.find(f => f.name.endsWith('.csv'));

    if (csvFile) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const text = e.target?.result as string;
        const listData = parseCSV(text);
        const entries = listData.map(row => ({
          name: row['product code'] || row.productcode || row.sku || 'Unknown',
          path: `List Upload / ${row.brand || 'No Brand'}`
        }));
        processEntries(entries);
      };
      reader.readAsText(csvFile);
    } else {
      const entries = files
        .filter(f => f.type.startsWith('image/') || f.name.match(/\.(jpg|jpeg|png|webp|gif)$/i))
        .map(f => ({ name: f.name, path: f.webkitRelativePath || f.name }));
      processEntries(entries);
    }
  }, [processEntries]);

  const stats = {
    total: results.length,
    success: results.filter(r => r.status === 'SUCCESS').length,
    fuzzy: results.filter(r => r.status === 'FUZZY').length,
    failure: results.filter(r => r.status === 'FAILURE').length
  };

  return (
    <div className="min-h-screen bg-slate-50 p-4 md:p-10 font-sans">
      <div className="max-w-7xl mx-auto space-y-8">
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h1 className="text-3xl font-bold text-slate-900 tracking-tight">ERP Filename Validator</h1>
            <p className="text-slate-500 mt-1">Extract product segments and validate against master data.</p>
          </div>
          <div className="flex items-center gap-3">
            <div className={`h-3 w-3 rounded-full ${status === FileStatus.PROCESSING ? 'bg-indigo-500 animate-pulse' : 'bg-green-500'}`} />
            <span className="text-sm font-semibold text-slate-700 uppercase tracking-wider">{status}</span>
          </div>
        </header>

        <section className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 space-y-4">
            <div className="flex items-center gap-2 mb-2">
              <div className="bg-slate-100 p-2 rounded-lg text-slate-600">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                </svg>
              </div>
              <h2 className="font-bold text-lg text-slate-800">1. ERP Master Data</h2>
            </div>
            <FileUploadZone label="Upload ERP CSV" onFilesSelected={handleERPUpload} accept=".csv" />
            {erpFileName && <div className="text-xs font-medium text-green-700 bg-green-50 p-2 rounded border border-green-100">✔ Linked: {erpFileName} ({erpData.length} records)</div>}
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 space-y-4">
            <div className="flex items-center gap-2 mb-2">
              <div className="bg-slate-100 p-2 rounded-lg text-slate-600">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                </svg>
              </div>
              <h2 className="font-bold text-lg text-slate-800">2. Imagery or Product List</h2>
            </div>
            <FileUploadZone 
              label="Upload Images, Folder, or Product CSV" 
              onFilesSelected={handleFileProcessing} 
              isFolder={true}
              accept="image/*,.csv"
            />
          </div>
        </section>

        {results.length > 0 && (
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            {[
              { label: 'Total', value: stats.total, color: 'indigo' },
              { label: 'Exact', value: stats.success, color: 'green' },
              { label: 'Fuzzy', value: stats.fuzzy, color: 'orange' },
              { label: 'Fail', value: stats.failure, color: 'red' }
            ].map(stat => (
              <div key={stat.label} className={`bg-white p-4 rounded-xl border-l-4 border-${stat.color}-500 shadow-sm`}>
                <p className="text-slate-500 text-[10px] font-bold uppercase">{stat.label}</p>
                <p className="text-xl font-black text-slate-800">{stat.value}</p>
              </div>
            ))}
          </div>
        )}

        <main className="space-y-4">
          <ResultsTable results={results} />
        </main>
      </div>
    </div>
  );
};

