            <div className="flex items-center gap-2 px-3 py-1.5 bg-white border border-slate-200 rounded-xl shadow-sm">
              <div className={`h-2 w-2 rounded-full ${status === FileStatus.PROCESSING || syncLoading ? 'bg-indigo-500 animate-pulse' : 'bg-green-500'}`} />
