                  syncLoading 
                    ? 'bg-slate-100 text-slate-400 cursor-not-allowed' 
                    : 'bg-slate-900 text-white hover:bg-black active:scale-[0.98]'
                }`}
              >
                {syncLoading ? (
                  <div className="h-4 w-4 border-2 border-slate-300 border-t-white rounded-full animate-spin" />
