};

export default App;

import React, { useState, useCallback } from 'react';
import FileUploadZone from './components/FileUploadZone';
import ResultsTable from './components/ResultsTable';
import { ERPRecord, MatchResult, FileStatus } from './types';
import { parseFilename, parseCSV } from './utils/parser';
import { findBestFuzzyMatch } from './utils/fuzzy';

// Databricks Configuration Placeholders
const DEFAULT_DATABRICKS_HOST = "adb-12345.azuredatabricks.net";
const DEFAULT_HTTP_PATH = "/sql/1.0/warehouses/your-warehouse-id";
const DEFAULT_QUERY = "SELECT * FROM sportsdirect_sql.dbo.ap21_product LIMIT 5000";

const App: React.FC = () => {
  const [erpData, setErpData] = useState<ERPRecord[]>([]);
  const [results, setResults] = useState<MatchResult[]>([]);
  const [status, setStatus] = useState<FileStatus>(FileStatus.IDLE);
  const [syncLoading, setSyncLoading] = useState(false);
  const [lastSync, setLastSync] = useState<string | null>(null);
  const [syncError, setSyncError] = useState<string | null>(null);

  // Configuration State
  const [host, setHost] = useState(DEFAULT_DATABRICKS_HOST);
  const [path, setPath] = useState(DEFAULT_HTTP_PATH);
  const [token, setToken] = useState(""); 

  const fetchDatabricksData = async () => {
    if (!token) {
      setSyncError("Please provide a Databricks Access Token.");
      return;
    }

    setSyncLoading(true);
    setSyncError(null);
    try {
      const warehouseId = path.split('/').pop();

      const response = await fetch(`https://${host}/api/2.0/sql/statements`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          warehouse_id: warehouseId,
          statement: DEFAULT_QUERY,
          disposition: "INLINE"
        })
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.message || "Failed to fetch from Databricks");
      }

      const result = await response.json();

      if (!result.manifest || !result.result?.data_array) {
        throw new Error("Invalid response format from Databricks. Check permissions/query.");
      }

      const columns = result.manifest.schema.columns.map((c: any) => c.name.toLowerCase());
      const dataArray = result.result.data_array;

      const sanitizedData: ERPRecord[] = dataArray.map((row: any[]) => {
        const rowObj: any = {};
        columns.forEach((col: string, idx: number) => {
          rowObj[col] = row[idx];
        });

        return {
          productCode: String(rowObj.productcode || rowObj.sku || rowObj['product code'] || '').toUpperCase().trim(),
          brand: String(rowObj.brand || '').toUpperCase().trim(),
          colorName: String(rowObj.colorname || rowObj.color || rowObj['color name'] || '').trim()
        };
      }).filter((r: ERPRecord) => r.productCode);

      if (sanitizedData.length === 0) {
        throw new Error("No valid records found in the specified table/query.");
      }

      setErpData(sanitizedData);
      setLastSync(new Date().toLocaleTimeString());
      setSyncError(null);
    } catch (error: any) {
      console.error("Databricks Sync Error:", error);
      setSyncError(error.message);
      setErpData([]);
    } finally {
      setSyncLoading(false);
    }
  };

  const processEntries = useCallback((entries: {name: string, path: string}[]) => {
    if (erpData.length === 0) {
      alert("ERP data is empty. Please sync from Databricks first.");
      setStatus(FileStatus.IDLE);
      return;
    }

    setStatus(FileStatus.PROCESSING);

    // Using requestAnimationFrame to ensure UI updates before heavy processing
    requestAnimationFrame(() => {
      setTimeout(() => {
        const extracted = entries.map(entry => parseFilename(entry.name, entry.path));
        const erpCodes = erpData.map(d => d.productCode);

        const matchedResults: MatchResult[] = extracted.map(info => {
          const attempts = info.candidateCodes;
          let directMatch: ERPRecord | undefined = undefined;
          let matchedAtStage: string | undefined = undefined;

          // Stage 1: Direct Match
          for (const candidate of attempts) {
            const found = erpData.find(d => d.productCode === candidate);
            if (found) {
              directMatch = found;
              matchedAtStage = candidate;
              break; 
            }
          }

          if (directMatch && matchedAtStage) {
            return {
              ...info,
              productCode: matchedAtStage,
              attempts,
              isMatch: true,
              isFuzzy: false,
              erpBrand: directMatch.brand,
              erpColorName: directMatch.colorName,
              status: 'SUCCESS' as const,
              reason: `Direct match: ${matchedAtStage}`
            };
          }

          // Stage 2: Fuzzy Match
          let bestFuzzy: { code: string; distance: number; source: string } | null = null;
          for (const candidate of attempts) {
            const fuzzy = findBestFuzzyMatch(candidate, erpCodes, 2);
            if (fuzzy && (!bestFuzzy || fuzzy.distance < bestFuzzy.distance)) {
              bestFuzzy = { ...fuzzy, source: candidate };
            }
          }

          if (bestFuzzy) {
            const fuzzyRecord = erpData.find(d => d.productCode === bestFuzzy!.code);
            return {
              ...info,
              attempts,
              isMatch: true,
              isFuzzy: true,
              fuzzyMatchCode: bestFuzzy.code,
              erpBrand: fuzzyRecord?.brand,
              erpColorName: fuzzyRecord?.colorName,
              status: 'FUZZY' as const,
              reason: `Fuzzy matched "${bestFuzzy.source}" to "${bestFuzzy.code}"`
            };
          }

          // Stage 3: Failure
          return {
            ...info,
            attempts,
            isMatch: false,
            isFuzzy: false,
            status: 'FAILURE' as const,
            reason: `No match for candidates: ${attempts.join(' | ')}`
          };
        });

        setResults(matchedResults);
        setStatus(FileStatus.COMPLETE);
      }, 50);
    });
  }, [erpData]);

  const handleFileProcessing = useCallback((files: File[]) => {
    if (files.length === 0) return;

    // Visual feedback immediately
    setStatus(FileStatus.PROCESSING);

    const csvFile = files.find(f => f.name.toLowerCase().endsWith('.csv'));

    if (csvFile) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const text = e.target?.result as string;
        const listData = parseCSV(text);
        const entries = listData.map(row => ({
          name: row['file name'] || row.filename || row.name || row['product code'] || 'Unknown',
          path: `CSV Upload / ${row.brand || 'No Brand'}`
        }));
        processEntries(entries);
      };
      reader.onerror = () => {
        alert("Failed to read CSV file.");
        setStatus(FileStatus.IDLE);
      };
      reader.readAsText(csvFile);
    } else {
      const entries = files
        .filter(f => f.type.startsWith('image/') || f.name.match(/\.(jpg|jpeg|png|webp|gif)$/i))
        .map(f => ({ name: f.name, path: f.webkitRelativePath || f.name }));

      if (entries.length === 0) {
        alert("No valid image files detected in your selection.");
        setStatus(FileStatus.IDLE);
        return;
      }
      processEntries(entries);
    }
  }, [processEntries]);

  const handleReset = () => {
    setResults([]);
    setErpData([]);
    setLastSync(null);
    setSyncError(null);
    setStatus(FileStatus.IDLE);
  };

  const downloadCSV = (data: string, filename: string) => {
    const blob = new Blob([data], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', filename);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const exportResults = () => {
    const successHeader = "File Name,Status,Extracted Color,Validated Code,ERP Color,ERP Brand\n";
    const failureHeader = "File Name,Brand Hint,Attempted Codes,Reason\n";

    const successRows = results
      .filter(r => r.status === 'SUCCESS' || r.status === 'FUZZY')
      .map(r => `"${r.fileName}","${r.status}","${r.colorCode}","${r.isFuzzy ? r.fuzzyMatchCode : r.productCode}","${r.erpColorName}","${r.erpBrand}"`)
      .join('\n');

    const failureRows = results
      .filter(r => r.status === 'FAILURE')
      .map(r => `"${r.fileName}","${r.brandHint}","${r.attempts.join(' | ')}","${r.reason}"`)
      .join('\n');

    if (successRows) {
      downloadCSV(successHeader + successRows, "validation_success.csv");
    }
    if (failureRows) {
      downloadCSV(failureHeader + failureRows, "validation_failed.csv");
    }
  };

  const stats = {
    total: results.length,
    success: results.filter(r => r.status === 'SUCCESS').length,
    fuzzy: results.filter(r => r.status === 'FUZZY').length,
    failure: results.filter(r => r.status === 'FAILURE').length
  };

  return (
    <div className="min-h-screen bg-slate-50 p-4 md:p-10 font-sans">
      <div className="max-w-7xl mx-auto space-y-8">
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="space-y-1">
            <h1 className="text-3xl font-bold text-slate-900 tracking-tight">ERP Filename Validator</h1>
            <p className="text-slate-500">Extract code, color, and brand from filenames with Databricks SQL Integration.</p>
          </div>

          <div className="flex flex-wrap items-center gap-3">
            {results.length > 0 && (
              <>
                <button 
                  onClick={handleReset}
                  className="px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-xl font-semibold text-sm hover:bg-slate-50 transition-colors shadow-sm flex items-center gap-2"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                  </svg>
                  Reset All
                </button>
                <button 
                  onClick={exportResults}
                  className="px-4 py-2 bg-indigo-600 text-white rounded-xl font-semibold text-sm hover:bg-indigo-700 transition-all shadow-md flex items-center gap-2"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                  </svg>
                  Export CSVs
                </button>
              </>
            )}
            <div className="flex items-center gap-2 px-3 py-1.5 bg-white border border-slate-200 rounded-xl shadow-sm">
              <div className={`h-2 w-2 rounded-full ${status === FileStatus.PROCESSING || syncLoading ? 'bg-indigo-500 animate-pulse' : (erpData.length > 0 ? 'bg-green-500' : 'bg-slate-300')}`} />
              <span className="text-[10px] font-black text-slate-700 uppercase tracking-widest">
                {syncLoading ? 'SYNCING...' : status}
              </span>
            </div>
          </div>
        </header>

        <section className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {/* Databricks Sync Panel */}
          <div className={`bg-white p-6 rounded-2xl shadow-sm border transition-all duration-300 ${syncError ? 'border-red-200' : erpData.length > 0 ? 'border-green-200 shadow-green-50/50' : 'border-slate-200'} space-y-4`}>
            <div className="flex items-center justify-between mb-2">
              <div className="flex items-center gap-2">
                <div className={`p-2 rounded-lg ${erpData.length > 0 ? 'bg-green-100 text-green-600' : 'bg-orange-100 text-orange-600'}`}>
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 7v10c0 2 1 3 3 3h10c2 0 3-1 3-3V7c0-2-1-3-3-3H7c-2 0-3 1-3 3z" />
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 17v-4m3 4v-6m3 6v-2" />
                  </svg>
                </div>
                <h2 className="font-bold text-lg text-slate-800">1. Databricks SQL Table</h2>
              </div>
              {lastSync && (
                <span className="text-[10px] text-green-600 font-bold uppercase tracking-wider bg-green-50 px-2 py-1 rounded">Synced {lastSync}</span>
              )}
            </div>

            <div className="space-y-3">
              <div className="grid grid-cols-1 gap-3">
                <div className="space-y-1">
                  <label className="text-[10px] uppercase font-bold text-slate-400 tracking-tight ml-1">Access Token</label>
                  <input 
                    type="password"
                    placeholder="dapi..."
                    className="w-full px-3 py-2 text-sm border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                    value={token}
                    onChange={(e) => setToken(e.target.value)}
                  />
                </div>
                <div className="grid grid-cols-2 gap-2">
                  <div className="space-y-1">
                    <label className="text-[10px] uppercase font-bold text-slate-400 tracking-tight ml-1">Server Host</label>
                    <input 
                      type="text"
                      className="w-full px-3 py-2 text-[11px] font-mono border border-slate-200 rounded-lg bg-slate-50"
                      value={host}
                      onChange={(e) => setHost(e.target.value)}
                    />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] uppercase font-bold text-slate-400 tracking-tight ml-1">HTTP Path</label>
                    <input 
                      type="text"
                      className="w-full px-3 py-2 text-[11px] font-mono border border-slate-200 rounded-lg bg-slate-50"
                      value={path}
                      onChange={(e) => setPath(e.target.value)}
                    />
                  </div>
                </div>
              </div>

              {syncError && (
                <div className="p-3 bg-red-50 border border-red-100 rounded-xl flex items-start gap-3 animate-in fade-in slide-in-from-top-1">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-red-500 shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                  <div className="flex flex-col">
                    <p className="text-xs font-bold text-red-700">Sync Failed</p>
                    <p className="text-[11px] text-red-600 leading-tight">{syncError}</p>
                  </div>
                </div>
              )}

              <button 
                onClick={fetchDatabricksData}
                disabled={syncLoading}
                className={`w-full py-3 rounded-xl font-bold text-sm flex items-center justify-center gap-2 transition-all shadow-sm ${
                  syncLoading 
                    ? 'bg-slate-100 text-slate-400 cursor-not-allowed' 
                    : erpData.length > 0 
                      ? 'bg-indigo-50 text-indigo-700 border border-indigo-200 hover:bg-indigo-100'
                      : 'bg-slate-900 text-white hover:bg-black active:scale-[0.98]'
                }`}
              >
                {syncLoading ? (
                  <div className="h-4 w-4 border-2 border-slate-300 border-t-white rounded-full animate-spin" />
                ) : (
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                  </svg>
                )}
                {syncLoading ? 'Connecting...' : erpData.length > 0 ? 'Refresh from Databricks' : 'Sync from Databricks'}
              </button>

              {erpData.length > 0 && !syncError && (
                <div className="text-[11px] font-medium text-green-700 bg-green-50 p-3 rounded-xl border border-green-100 flex items-center justify-between animate-in zoom-in-95 duration-300">
                  <div className="flex items-center gap-2">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                    </svg>
                    <span>Connected to Table</span>
                  </div>
                  <span className="bg-green-200 px-2 py-0.5 rounded-full font-bold">{erpData.length} records</span>
                </div>
              )}
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 space-y-4">
            <div className="flex items-center gap-2 mb-2">
              <div className="bg-slate-100 p-2 rounded-lg text-slate-600">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                </svg>
              </div>
              <h2 className="font-bold text-lg text-slate-800">2. Filenames to Validate</h2>
            </div>
            <FileUploadZone 
              label="Select Imagery Folder or Upload Files" 
