            {results.length === 0 && erpData.length > 0 && (
              <p className="text-center text-xs text-slate-400">Ready to validate files against {erpData.length} records</p>
            )}
          </div>
        </section>

        {results.length > 0 && (
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 animate-in fade-in slide-in-from-bottom-2 duration-500">
            {[
              { label: 'Total', value: stats.total, color: 'indigo' },
              { label: 'Success', value: stats.success, color: 'green' },
              { label: 'Fuzzy', value: stats.fuzzy, color: 'orange' },
              { label: 'Fail', value: stats.failure, color: 'red' }
