import React, { useState, useCallback } from 'react';
import FileUploadZone from './components/FileUploadZone';
import ResultsTable from './components/ResultsTable';
import { ERPRecord, MatchResult, FileStatus, ExtractedInfo } from './types';
import { parseFilename, parseCSV } from './utils/parser';
import { findBestFuzzyMatch } from './utils/fuzzy';

// Configuration Defaults
const DEFAULT_DATABRICKS_HOST = "adb-12345.azuredatabricks.net";
const DEFAULT_HTTP_PATH = "/sql/1.0/warehouses/your-warehouse-id";

const App: React.FC = () => {
  const [results, setResults] = useState<MatchResult[]>([]);
  const [status, setStatus] = useState<FileStatus>(FileStatus.IDLE);
  const [syncError, setSyncError] = useState<string | null>(null);

  // Configuration State
  const [host, setHost] = useState(DEFAULT_DATABRICKS_HOST);
  const [path, setPath] = useState(DEFAULT_HTTP_PATH);
  const [token, setToken] = useState(""); 

  // Helper to chunk arrays for SQL limits (e.g., IN clause limit)
  const chunkArray = (array: string[], size: number) => {
    const chunked = [];
    for (let i = 0; i < array.length; i += size) {
      chunked.push(array.slice(i, i + size));
    }
    return chunked;
  };

  const fetchDatabricksRecords = async (candidateCodes: string[]): Promise<ERPRecord[]> => {
    if (!token) throw new Error("Missing Access Token");
    if (candidateCodes.length === 0) return [];

    const warehouseId = path.split('/').pop();
    const PROXY_URL = "https://databricks-proxy-725829572897.europe-west1.run.app"; 

    // Sanitize codes to prevent SQL injection issues within the string builder
    const safeCodes = candidateCodes
      .map(c => c.replace(/'/g, "''").trim())
      .filter(c => c.length > 0);

    // If no valid codes, return empty
    if (safeCodes.length === 0) return [];

    // Construct dynamic query
    // We look for the candidate code in both clrcode (product code) AND styleidx (style code)
    const codeList = safeCodes.map(c => `'${c}'`).join(',');

    const query = `
      SELECT styleidx, clrcode, stylebrand, stylecolour, stylename
      FROM sportsdirect_sql.dbo.ap21_product
      WHERE styleidx IN (${codeList}) 
         OR clrcode IN (${codeList})
    `;

    try {
      const response = await fetch(PROXY_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          host: host,
          warehouseId: warehouseId,
          token: token,
          statement: query
        })
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.message || "Failed to fetch from Databricks");
      }

      const result = await response.json();

      if (!result.manifest || !result.result?.data_array) return [];

      const columns = result.manifest.schema.columns.map((c: any) => c.name.toLowerCase());
      const dataArray = result.result.data_array;

      return dataArray.map((row: any[]) => {
        const rowObj: any = {};
        columns.forEach((col: string, idx: number) => {
          rowObj[col] = row[idx];
        });

        // Map multiple potential columns to our internal structure
        // We create two records if necessary or just normalize here.
        // For simplicity, we assume the row represents one valid SKU.
        return {
          productCode: String(rowObj.clrcode || rowObj.styleidx || '').toUpperCase().trim(),
          brand: String(rowObj.stylebrand || '').toUpperCase().trim(),
          colorName: String(rowObj.stylecolour || rowObj.color || '').trim(),
          productName: String(rowObj.stylename || '').trim()
        };
      });

    } catch (error) {
      console.error("Batch Fetch Error", error);
      throw error;
    }
  };

  const processEntries = useCallback(async (entries: {name: string, path: string}[]) => {
    if (!token) {
      setSyncError("Please enter your Databricks Access Token to process files.");
      return;
    }

    setSyncError(null);
    setStatus(FileStatus.PARSING);

    // 1. Parse all filenames to get candidates
    const extractedInfos = entries.map(entry => parseFilename(entry.name, entry.path));

    // 2. Collect all unique candidate codes to query
    const allCandidates = new Set<string>();
    extractedInfos.forEach(info => {
      info.candidateCodes.forEach(code => allCandidates.add(code));
    });

    const uniqueCandidatesList = Array.from(allCandidates);

    if (uniqueCandidatesList.length === 0) {
      setSyncError("Could not extract any potential product codes from the filenames.");
      setStatus(FileStatus.IDLE);
      return;
    }

    setStatus(FileStatus.QUERYING);

    try {
      // 3. Batch Query Databricks (Chunking to avoid massive SQL queries)
      // Databricks statement limits vary, keeping chunks safe at ~200 codes per query
      const chunks = chunkArray(uniqueCandidatesList, 200);
      let fetchedRecords: ERPRecord[] = [];

      // Execute chunks in parallel (or sequential if rate limits are tight)
      // Parallel is faster for user experience
      const promises = chunks.map(chunk => fetchDatabricksRecords(chunk));
      const resultsArray = await Promise.all(promises);

      resultsArray.forEach(batch => {
        fetchedRecords = [...fetchedRecords, ...batch];
      });

      // Deduplicate fetched records based on productCode
      const uniqueRecordsMap = new Map<string, ERPRecord>();
      fetchedRecords.forEach(r => uniqueRecordsMap.set(r.productCode, r));
      const erpData = Array.from(uniqueRecordsMap.values());

      setStatus(FileStatus.PROCESSING);

      // 4. Validate matches locally against the fetched subset
      const matchedResults: MatchResult[] = extractedInfos.map(info => {
        const attempts = info.candidateCodes;
        let directMatch: ERPRecord | undefined = undefined;
        let matchedAtStage: string | undefined = undefined;

        // Stage 1: Direct Match
        for (const candidate of attempts) {
          const found = erpData.find(d => d.productCode === candidate);
          if (found) {
            directMatch = found;
            matchedAtStage = candidate;
            break; 
          }
        }

        if (directMatch && matchedAtStage) {
          return {
            ...info,
            productCode: matchedAtStage,
            attempts,
            isMatch: true,
            isFuzzy: false,
            erpBrand: directMatch.brand,
            erpColorName: directMatch.colorName,
            erpProductName: directMatch.productName,
            status: 'SUCCESS' as const,
            reason: `Direct match: ${matchedAtStage}`
          };
        }

        // Stage 2: Fuzzy Match
        // Note: Fuzzy match only works against the subset we retrieved. 
        // If the code was wildly wrong and not in the "IN" clause, we won't find it here.
        // This is a trade-off for not downloading the whole DB.
        const erpCodes = erpData.map(d => d.productCode);
        let bestFuzzy: { code: string; distance: number; source: string } | null = null;
        for (const candidate of attempts) {
          const fuzzy = findBestFuzzyMatch(candidate, erpCodes, 2);
          if (fuzzy && (!bestFuzzy || fuzzy.distance < bestFuzzy.distance)) {
            bestFuzzy = { ...fuzzy, source: candidate };
          }
        }

        if (bestFuzzy) {
          const fuzzyRecord = erpData.find(d => d.productCode === bestFuzzy!.code);
          return {
            ...info,
            attempts,
            isMatch: true,
            isFuzzy: true,
            fuzzyMatchCode: bestFuzzy.code,
            erpBrand: fuzzyRecord?.brand,
            erpColorName: fuzzyRecord?.colorName,
            erpProductName: fuzzyRecord?.productName,
            status: 'FUZZY' as const,
            reason: `Fuzzy matched "${bestFuzzy.source}" to "${bestFuzzy.code}"`
          };
        }

        // Stage 3: Failure
        return {
          ...info,
          attempts,
          isMatch: false,
          isFuzzy: false,
          status: 'FAILURE' as const,
          reason: `No match found in ERP for: ${attempts.join(', ')}`
        };
      });

      setResults(matchedResults);
      setStatus(FileStatus.COMPLETE);

    } catch (e: any) {
      console.error(e);
      setSyncError("Error querying Databricks: " + e.message);
      setStatus(FileStatus.ERROR);
    }
  }, [token, host, path]);

  const handleFileProcessing = useCallback((files: File[]) => {
    if (files.length === 0) return;

    const csvFile = files.find(f => f.name.toLowerCase().endsWith('.csv'));

    if (csvFile) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const text = e.target?.result as string;
        const listData = parseCSV(text);
        const entries = listData.map(row => ({
          name: row['file name'] || row.filename || row.name || row['product code'] || 'Unknown',
          path: `CSV Upload / ${row.brand || 'No Brand'}`
        }));
        processEntries(entries);
      };
      reader.onerror = () => {
        alert("Failed to read CSV file.");
      };
      reader.readAsText(csvFile);
    } else {
      const entries = files
        .filter(f => f.type.startsWith('image/') || f.name.match(/\.(jpg|jpeg|png|webp|gif)$/i))
        .map(f => ({ name: f.name, path: f.webkitRelativePath || f.name }));

      if (entries.length === 0) {
        alert("No valid image files detected in your selection.");
        return;
      }
      processEntries(entries);
    }
  }, [processEntries]);

  const handleReset = () => {
    setResults([]);
    setSyncError(null);
    setStatus(FileStatus.IDLE);
  };

  const downloadCSV = (data: string, filename: string) => {
    const blob = new Blob([data], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', filename);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const exportResults = () => {
    const successHeader = "File Name,Status,Extracted Color,Validated Code,ERP Product Name,ERP Color,ERP Brand\n";
    const failureHeader = "File Name,Brand Hint,Attempted Codes,Reason\n";

    const successRows = results
      .filter(r => r.status === 'SUCCESS' || r.status === 'FUZZY')
      .map(r => `"${r.fileName}","${r.status}","${r.colorCode}","${r.isFuzzy ? r.fuzzyMatchCode : r.productCode}","${r.erpProductName || ''}","${r.erpColorName}","${r.erpBrand}"`)
      .join('\n');

    const failureRows = results
      .filter(r => r.status === 'FAILURE')
      .map(r => `"${r.fileName}","${r.brandHint}","${r.attempts.join(' | ')}","${r.reason}"`)
      .join('\n');

    if (successRows) {
      downloadCSV(successHeader + successRows, "validation_success.csv");
    }
    if (failureRows) {
      downloadCSV(failureHeader + failureRows, "validation_failed.csv");
    }
  };

  const stats = {
    total: results.length,
    success: results.filter(r => r.status === 'SUCCESS').length,
    fuzzy: results.filter(r => r.status === 'FUZZY').length,
    failure: results.filter(r => r.status === 'FAILURE').length
  };

  return (
    <div className="min-h-screen bg-slate-50 p-4 md:p-10 font-sans">
      <div className="max-w-7xl mx-auto space-y-8">
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="space-y-1">
            <h1 className="text-3xl font-bold text-slate-900 tracking-tight">ERP Filename Validator</h1>
            <p className="text-slate-500">Auto-query Databricks for Product Code, Name, and Color verification.</p>
          </div>

          <div className="flex flex-wrap items-center gap-3">
            {results.length > 0 && (
              <>
                <button 
                  onClick={handleReset}
                  className="px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-xl font-semibold text-sm hover:bg-slate-50 transition-colors shadow-sm flex items-center gap-2"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                  </svg>
                  Reset All
                </button>
                <button 
                  onClick={exportResults}
                  className="px-4 py-2 bg-indigo-600 text-white rounded-xl font-semibold text-sm hover:bg-indigo-700 transition-all shadow-md flex items-center gap-2"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
