import React, { useState, useCallback } from 'react';
import FileUploadZone from './components/FileUploadZone';
import ResultsTable from './components/ResultsTable';
import { ERPRecord, MatchResult, FileStatus, ExtractedInfo } from './types';
import { parseFilename, parseCSV } from './utils/parser';
import { findBestFuzzyMatch } from './utils/fuzzy';

// Configuration Defaults
const DEFAULT_DATABRICKS_HOST = "adb-4215830024773554.14.azuredatabricks.net";
const DEFAULT_HTTP_PATH = "b848132ea9c3d9df";

const App: React.FC = () => {
  const [results, setResults] = useState<MatchResult[]>([]);
  const [status, setStatus] = useState<FileStatus>(FileStatus.IDLE);
  const [syncError, setSyncError] = useState<string | null>(null);

  // Configuration State
  const [host, setHost] = useState(DEFAULT_DATABRICKS_HOST);
  const [path, setPath] = useState(DEFAULT_HTTP_PATH);
  const [token, setToken] = useState(""); 

  // Helper to chunk arrays for SQL limits (e.g., IN clause limit)
  const chunkArray = (array: string[], size: number) => {
    const chunked = [];
    for (let i = 0; i < array.length; i += size) {
      chunked.push(array.slice(i, i + size));
    }
    return chunked;
  };

  const fetchDatabricksRecords = async (candidateCodes: string[]): Promise<ERPRecord[]> => {
    if (!token) throw new Error("Missing Access Token");
    if (candidateCodes.length === 0) return [];

    const warehouseId = path.split('/').pop();
    const PROXY_URL = "https://databricks-proxy-725829572897.europe-west1.run.app"; 

    // Sanitize codes to prevent SQL injection issues within the string builder
    const safeCodes = candidateCodes
      .map(c => c.replace(/'/g, "''").trim())
      .filter(c => c.length > 0);

    // If no valid codes, return empty
    if (safeCodes.length === 0) return [];

    // Construct dynamic query
    // Using StyleCategory as requested instead of StyleColour
    const codeList = safeCodes.map(c => `'${c}'`).join(',');

    const query = `
      SELECT StyleCode, CLRCode, StyleBrand, StyleCategory, Name
      FROM sportsdirect_sql.dbo.ap21_product
      WHERE StyleCode IN (${codeList}) 
         OR CLRCode IN (${codeList})
    `;

    try {
      const response = await fetch(PROXY_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          host: host,
          warehouseId: warehouseId,
          token: token,
          statement: query
        })
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.message || "Failed to fetch from Databricks");
      }

      const result = await response.json();

      if (!result.manifest || !result.result?.data_array) return [];

      const columns = result.manifest.schema.columns.map((c: any) => c.name.toLowerCase());
      const dataArray = result.result.data_array;

      return dataArray.map((row: any[]) => {
        const rowObj: any = {};
        columns.forEach((col: string, idx: number) => {
          rowObj[col] = row[idx];
        });

        // Exact column mapping based on requested SQL
        const styleCode = String(rowObj.stylecode || '').toUpperCase().trim();
        const clrCode = String(rowObj.clrcode || '').toUpperCase().trim();
        const brand = String(rowObj.stylebrand || '').toUpperCase().trim();
        const styleCategory = String(rowObj.stylecategory || '').trim();
        const productName = String(rowObj.name || '').trim();

        return {
          productCode: styleCode, // StyleCode is the primary
          styleCode,
          clrCode,
          brand,
          styleCategory,
          productName
        };
      });

    } catch (error) {
      console.error("Batch Fetch Error", error);
      throw error;
    }
  };

  const processEntries = useCallback(async (entries: {name: string, path: string}[]) => {
    if (!token) {
      setSyncError("Please enter your Databricks Access Token to process files.");
      return;
    }

    setSyncError(null);
    setStatus(FileStatus.PARSING);

    // 1. Parse all filenames to get candidates
    const extractedInfos = entries.map(entry => parseFilename(entry.name, entry.path));

    // 2. Collect all unique candidate codes to query
    const allCandidates = new Set<string>();
    extractedInfos.forEach(info => {
      info.candidateCodes.forEach(code => allCandidates.add(code));
    });

    const uniqueCandidatesList = Array.from(allCandidates);

    if (uniqueCandidatesList.length === 0) {
      setSyncError("Could not extract any potential product codes from the filenames.");
      setStatus(FileStatus.IDLE);
      return;
    }

    setStatus(FileStatus.QUERYING);

    try {
      // 3. Batch Query Databricks (Chunking to avoid massive SQL queries)
      // Databricks statement limits vary, keeping chunks safe at ~200 codes per query
      const chunks = chunkArray(uniqueCandidatesList, 200);
      let fetchedRecords: ERPRecord[] = [];

      // Execute chunks in parallel
      const promises = chunks.map(chunk => fetchDatabricksRecords(chunk));
      const resultsArray = await Promise.all(promises);

      resultsArray.forEach(batch => {
        fetchedRecords = [...fetchedRecords, ...batch];
      });

      // Deduplicate fetched records
      const erpData = fetchedRecords;

      setStatus(FileStatus.PROCESSING);

      // 4. Validate matches locally against the fetched subset
      const matchedResults: MatchResult[] = extractedInfos.map(info => {
        const attempts = info.candidateCodes;
        let directMatch: ERPRecord | undefined = undefined;
        let matchedAtStage: string | undefined = undefined;

        // Stage 1: Direct Match
        // We check against BOTH StyleCode and CLRCode
        for (const candidate of attempts) {
          const found = erpData.find(d => d.styleCode === candidate || d.clrCode === candidate);
          if (found) {
            directMatch = found;
            matchedAtStage = candidate;
            break; 
          }
        }

        if (directMatch && matchedAtStage) {
          return {
            ...info,
            productCode: matchedAtStage,
            attempts,
            isMatch: true,
            isFuzzy: false,
            erpBrand: directMatch.brand,
            erpStyleCategory: directMatch.styleCategory,
            erpProductName: directMatch.productName,
            status: 'SUCCESS' as const,
            reason: `Direct match: ${matchedAtStage}`
          };
        }

        // Stage 2: Fuzzy Match
        // We create a pool of all valid codes (both styles and CLRs) to fuzzy match against
        const allErpCodes = erpData.flatMap(d => [d.styleCode, d.clrCode]).filter(Boolean);

        let bestFuzzy: { code: string; distance: number; source: string } | null = null;
        for (const candidate of attempts) {
          const fuzzy = findBestFuzzyMatch(candidate, allErpCodes, 2);
          if (fuzzy && (!bestFuzzy || fuzzy.distance < bestFuzzy.distance)) {
            bestFuzzy = { ...fuzzy, source: candidate };
          }
        }

        if (bestFuzzy) {
          // Find the record that owns this fuzzy code
          const fuzzyRecord = erpData.find(d => d.styleCode === bestFuzzy!.code || d.clrCode === bestFuzzy!.code);
          return {
            ...info,
            attempts,
            isMatch: true,
            isFuzzy: true,
            fuzzyMatchCode: bestFuzzy.code,
            erpBrand: fuzzyRecord?.brand,
            erpStyleCategory: fuzzyRecord?.styleCategory,
            erpProductName: fuzzyRecord?.productName,
            status: 'FUZZY' as const,
            reason: `Fuzzy matched "${bestFuzzy.source}" to "${bestFuzzy.code}"`
          };
        }

        // Stage 3: Failure
        return {
          ...info,
          attempts,
          isMatch: false,
          isFuzzy: false,
          status: 'FAILURE' as const,
          reason: `No match found in ERP for: ${attempts.join(', ')}`
        };
      });

      setResults(matchedResults);
      setStatus(FileStatus.COMPLETE);

    } catch (e: any) {
      console.error(e);
      setSyncError("Error querying Databricks: " + e.message);
      setStatus(FileStatus.ERROR);
    }
  }, [token, host, path]);

  const handleFileProcessing = useCallback((files: File[]) => {
    if (files.length === 0) return;

    const csvFile = files.find(f => f.name.toLowerCase().endsWith('.csv'));

    if (csvFile) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const text = e.target?.result as string;
        const listData = parseCSV(text);
        const entries = listData.map(row => ({
          name: row['file name'] || row.filename || row.name || row['product code'] || 'Unknown',
          path: `CSV Upload / ${row.brand || 'No Brand'}`
        }));
        processEntries(entries);
      };
      reader.onerror = () => {
        alert("Failed to read CSV file.");
      };
      reader.readAsText(csvFile);
    } else {
      const entries = files
        .filter(f => f.type.startsWith('image/') || f.name.match(/\.(jpg|jpeg|png|webp|gif)$/i))
        .map(f => ({ name: f.name, path: f.webkitRelativePath || f.name }));

      if (entries.length === 0) {
        alert("No valid image files detected in your selection.");
        return;
      }
      processEntries(entries);
    }
  }, [processEntries]);

  const handleReset = () => {
    setResults([]);
    setSyncError(null);
    setStatus(FileStatus.IDLE);
  };

  const downloadCSV = (data: string, filename: string) => {
    const blob = new Blob([data], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', filename);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const exportResults = () => {
    const successHeader = "File Name,Status,Extracted Color,Validated Code,ERP Product Name,ERP Category,ERP Brand\n";
    const failureHeader = "File Name,Brand Hint,Attempted Codes,Reason\n";

    const successRows = results
      .filter(r => r.status === 'SUCCESS' || r.status === 'FUZZY')
      .map(r => `"${r.fileName}","${r.status}","${r.colorCode}","${r.isFuzzy ? r.fuzzyMatchCode : r.productCode}","${r.erpProductName || ''}","${r.erpStyleCategory}","${r.erpBrand}"`)
      .join('\n');

    const failureRows = results
      .filter(r => r.status === 'FAILURE')
      .map(r => `"${r.fileName}","${r.brandHint}","${r.attempts.join(' | ')}","${r.reason}"`)
      .join('\n');

    if (successRows) {
      downloadCSV(successHeader + successRows, "validation_success.csv");
    }
    if (failureRows) {
      downloadCSV(failureHeader + failureRows, "validation_failed.csv");
    }
  };

  const stats = {
    total: results.length,
    success: results.filter(r => r.status === 'SUCCESS').length,
    fuzzy: results.filter(r => r.status === 'FUZZY').length,
    failure: results.filter(r => r.status === 'FAILURE').length
  };

  return (
    <div className="min-h-screen bg-slate-50 p-4 md:p-10 font-sans">
      <div className="max-w-7xl mx-auto space-y-8">
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="space-y-1">
            <h1 className="text-3xl font-bold text-slate-900 tracking-tight">ERP Filename Validator</h1>
            <p className="text-slate-500">Auto-query Databricks for Product Code, Name, and Category verification.</p>
          </div>

          <div className="flex flex-wrap items-center gap-3">
            {results.length > 0 && (
              <>
                <button 
                  onClick={handleReset}
                  className="px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-xl font-semibold text-sm hover:bg-slate-50 transition-colors shadow-sm flex items-center gap-2"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                  </svg>
                  Reset All
                </button>
                <button 
                  onClick={exportResults}
                  className="px-4 py-2 bg-indigo-600 text-white rounded-xl font-semibold text-sm hover:bg-indigo-700 transition-all shadow-md flex items-center gap-2"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                  </svg>
                  Export CSVs
                </button>
              </>
            )}
            <div className="flex items-center gap-2 px-3 py-1.5 bg-white border border-slate-200 rounded-xl shadow-sm">
              <div className={`h-2 w-2 rounded-full ${[FileStatus.PARSING, FileStatus.QUERYING, FileStatus.PROCESSING].includes(status) ? 'bg-indigo-500 animate-pulse' : (status === FileStatus.COMPLETE ? 'bg-green-500' : 'bg-slate-300')}`} />
              <span className="text-[10px] font-black text-slate-700 uppercase tracking-widest">
                {status}
              </span>
            </div>
          </div>
        </header>

        <section className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {/* Configuration Panel */}
          <div className={`bg-white p-6 rounded-2xl shadow-sm border transition-all duration-300 ${syncError ? 'border-red-200' : 'border-slate-200'} space-y-4`}>
            <div className="flex items-center justify-between mb-2">
              <div className="flex items-center gap-2">
                <div className="p-2 rounded-lg bg-slate-100 text-slate-600">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                  </svg>
                </div>
                <h2 className="font-bold text-lg text-slate-800">1. Connection Settings</h2>
              </div>
            </div>

            <div className="space-y-3">
              <div className="grid grid-cols-1 gap-3">
                <div className="space-y-1">
                  <label className="text-[10px] uppercase font-bold text-slate-400 tracking-tight ml-1">Access Token</label>
                  <input 
                    type="password"
                    placeholder="dapi..."
                    className="w-full px-3 py-2 text-sm border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                    value={token}
                    onChange={(e) => setToken(e.target.value)}
                  />
                </div>
                <div className="grid grid-cols-2 gap-2">
                  <div className="space-y-1">
                    <label className="text-[10px] uppercase font-bold text-slate-400 tracking-tight ml-1">Server Host</label>
                    <input 
                      type="text"
                      className="w-full px-3 py-2 text-[11px] font-mono border border-slate-200 rounded-lg bg-slate-50"
                      value={host}
                      onChange={(e) => setHost(e.target.value)}
                    />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] uppercase font-bold text-slate-400 tracking-tight ml-1">HTTP Path</label>
                    <input 
                      type="text"
                      className="w-full px-3 py-2 text-[11px] font-mono border border-slate-200 rounded-lg bg-slate-50"
                      value={path}
                      onChange={(e) => setPath(e.target.value)}
                    />
                  </div>
                </div>
              </div>

              {syncError && (
                <div className="p-3 bg-red-50 border border-red-100 rounded-xl flex items-start gap-3 animate-in fade-in slide-in-from-top-1">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-red-500 shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                  <div className="flex flex-col">
                    <p className="text-xs font-bold text-red-700">Config Error</p>
                    <p className="text-[11px] text-red-600 leading-tight">{syncError}</p>
                  </div>
                </div>
              )}

              <div className="text-[11px] text-slate-400 italic bg-slate-50 p-2 rounded border border-slate-100">
                Connection details are used only when you drop files to validate.
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 space-y-4">
            <div className="flex items-center gap-2 mb-2">
              <div className="bg-slate-100 p-2 rounded-lg text-slate-600">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                </svg>
              </div>
              <h2 className="font-bold text-lg text-slate-800">2. Drop Files to Query</h2>
            </div>
            <FileUploadZone 
              label="Upload Images/Folders" 
              onFilesSelected={handleFileProcessing} 
              isFolder={true}
              accept="image/*,.csv"
            />
            {status === FileStatus.QUERYING && (
              <div className="text-center py-2 animate-pulse">
                 <p className="text-xs font-bold text-indigo-600">Querying Databricks for matches...</p>
              </div>
            )}
          </div>
        </section>

        {results.length > 0 && (
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 animate-in fade-in slide-in-from-bottom-2 duration-500">
            {[
              { label: 'Total', value: stats.total, color: 'indigo' },
              { label: 'Success', value: stats.success, color: 'green' },
              { label: 'Fuzzy', value: stats.fuzzy, color: 'orange' },
              { label: 'Fail', value: stats.failure, color: 'red' }
            ].map(stat => (
              <div key={stat.label} className={`bg-white p-4 rounded-xl border-l-4 border-${stat.color}-500 shadow-sm ring-1 ring-slate-200`}>
                <p className="text-slate-500 text-[10px] font-bold uppercase tracking-tight">{stat.label}</p>
                <p className="text-2xl font-black text-slate-800">{stat.value}</p>
              </div>
            ))}
          </div>
        )}

        <main className="space-y-4 pb-20">
          <ResultsTable results={results} />
        </main>
      </div>
    </div>
  );
};

export default App;

export interface ERPRecord {
  productCode: string; // Primary display code (StyleCode)
  styleCode: string;   // Specific Style Code column
  clrCode: string;     // Specific CLR Code column
  brand: string;
  styleCategory: string; // Replaces colorName
  productName: string; 
}

export interface ExtractedInfo {
  fileName: string;
  fullPath: string;
  brandHint: string;
  candidateCodes: string[]; // Progressive fallback variants: [Base, Base-2, Base-2-3]
  productCode: string;      // The primary code found or the best guess from the filename
  colorCode: string;
  tokens: string[];
}

export interface MatchResult extends ExtractedInfo {
  isMatch: boolean;
  isFuzzy: boolean;
  erpBrand?: string;
  erpStyleCategory?: string;
  erpProductName?: string;
  fuzzyMatchCode?: string;
  status: 'SUCCESS' | 'FUZZY' | 'FAILURE';
  attempts: string[]; 
  reason?: string;    
}

export interface QueryLog {
  batchId: number;
  timestamp: string;
  statement: string;
  rawResponse: any;
  parsedCount: number;
  error?: string;
}

export enum FileStatus {
  IDLE = 'IDLE',
  PARSING = 'PARSING',
  QUERYING = 'QUERYING ERP',
  PROCESSING = 'VALIDATING',
  COMPLETE = 'COMPLETE',
  ERROR = 'ERROR'
}

import React, { useState, useCallback } from 'react';
import FileUploadZone from './components/FileUploadZone';
import ResultsTable from './components/ResultsTable';
import { ERPRecord, MatchResult, FileStatus, ExtractedInfo, QueryLog } from './types';
import { parseFilename, parseCSV } from './utils/parser';
import { findBestFuzzyMatch } from './utils/fuzzy';

// Configuration Defaults
const DEFAULT_DATABRICKS_HOST = "adb-4215830024773554.14.azuredatabricks.net";
const DEFAULT_HTTP_PATH = "b848132ea9c3d9df";

const App: React.FC = () => {
  const [results, setResults] = useState<MatchResult[]>([]);
  const [status, setStatus] = useState<FileStatus>(FileStatus.IDLE);
  const [syncError, setSyncError] = useState<string | null>(null);
  const [debugLogs, setDebugLogs] = useState<QueryLog[]>([]);

  // Configuration State
  const [host, setHost] = useState(DEFAULT_DATABRICKS_HOST);
  const [path, setPath] = useState(DEFAULT_HTTP_PATH);
  const [token, setToken] = useState(""); 

  // Helper to chunk arrays for SQL limits (e.g., IN clause limit)
  const chunkArray = (array: string[], size: number) => {
    const chunked = [];
    for (let i = 0; i < array.length; i += size) {
      chunked.push(array.slice(i, i + size));
    }
    return chunked;
  };

  const fetchDatabricksRecords = async (candidateCodes: string[], batchId: number): Promise<{ records: ERPRecord[], log: QueryLog }> => {
    if (!token) throw new Error("Missing Access Token");

    // Default empty log structure
    const logEntry: QueryLog = {
      batchId,
      timestamp: new Date().toISOString(),
      statement: "",
      rawResponse: null,
      parsedCount: 0
    };

    if (candidateCodes.length === 0) return { records: [], log: logEntry };

    const warehouseId = path.split('/').pop();
    const PROXY_URL = "https://databricks-proxy-725829572897.europe-west1.run.app"; 

    // Sanitize codes to prevent SQL injection issues within the string builder
    const safeCodes = candidateCodes
      .map(c => c.replace(/'/g, "''").trim())
      .filter(c => c.length > 0);

    // If no valid codes, return empty
    if (safeCodes.length === 0) return { records: [], log: logEntry };

    // Construct dynamic query
    const codeList = safeCodes.map(c => `'${c}'`).join(',');

    const query = `
      SELECT StyleCode, CLRCode, StyleBrand, StyleCategory, Name
      FROM sportsdirect_sql.dbo.ap21_product
      WHERE StyleCode IN (${codeList}) 
         OR CLRCode IN (${codeList})
    `;

    logEntry.statement = query;

    try {
      const response = await fetch(PROXY_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          host: host,
          warehouseId: warehouseId,
          token: token,
          statement: query
        })
      });

      if (!response.ok) {
        const errorData = await response.json();
        logEntry.error = errorData.message || "HTTP Error";
        logEntry.rawResponse = errorData;
        throw new Error(logEntry.error);
      }

      const result = await response.json();
      logEntry.rawResponse = result; // Store full raw response for debugging

      if (!result.manifest || !result.result?.data_array) {
        return { records: [], log: logEntry };
      }

      const columns = result.manifest.schema.columns.map((c: any) => c.name.toLowerCase());
      const dataArray = result.result.data_array;

      const parsedRecords = dataArray.map((row: any[]) => {
        const rowObj: any = {};
        columns.forEach((col: string, idx: number) => {
          rowObj[col] = row[idx];
        });

        // Exact column mapping based on requested SQL
        // Note: Databricks often returns column names in lowercase in the manifest
        const styleCode = String(rowObj.stylecode || '').toUpperCase().trim();
        const clrCode = String(rowObj.clrcode || '').toUpperCase().trim();
        const brand = String(rowObj.stylebrand || '').toUpperCase().trim();
        const styleCategory = String(rowObj.stylecategory || '').trim();
        const productName = String(rowObj.name || '').trim();

        return {
          productCode: styleCode, // StyleCode is the primary
          styleCode,
          clrCode,
          brand,
          styleCategory,
          productName
        };
      });

      logEntry.parsedCount = parsedRecords.length;
      return { records: parsedRecords, log: logEntry };

    } catch (error: any) {
      console.error("Batch Fetch Error", error);
      logEntry.error = error.message;
      return { records: [], log: logEntry };
    }
  };

  const processEntries = useCallback(async (entries: {name: string, path: string}[]) => {
    if (!token) {
      setSyncError("Please enter your Databricks Access Token to process files.");
      return;
    }

    setSyncError(null);
    setDebugLogs([]); // Clear logs on new run
    setStatus(FileStatus.PARSING);

    // 1. Parse all filenames to get candidates
    const extractedInfos = entries.map(entry => parseFilename(entry.name, entry.path));

    // 2. Collect all unique candidate codes to query
    const allCandidates = new Set<string>();
    extractedInfos.forEach(info => {
      info.candidateCodes.forEach(code => allCandidates.add(code));
    });

    const uniqueCandidatesList = Array.from(allCandidates);

    if (uniqueCandidatesList.length === 0) {
      setSyncError("Could not extract any potential product codes from the filenames.");
      setStatus(FileStatus.IDLE);
      return;
    }

    setStatus(FileStatus.QUERYING);

    try {
      // 3. Batch Query Databricks (Chunking to avoid massive SQL queries)
      // Databricks statement limits vary, keeping chunks safe at ~200 codes per query
      const chunks = chunkArray(uniqueCandidatesList, 200);
      let fetchedRecords: ERPRecord[] = [];
      let newLogs: QueryLog[] = [];

      // Execute chunks in parallel
      const promises = chunks.map((chunk, index) => fetchDatabricksRecords(chunk, index));
      const resultsArray = await Promise.all(promises);

      resultsArray.forEach(batch => {
        fetchedRecords = [...fetchedRecords, ...batch.records];
        newLogs.push(batch.log);
      });

      setDebugLogs(newLogs);

      // Deduplicate fetched records
      const erpData = fetchedRecords;

      setStatus(FileStatus.PROCESSING);

      // 4. Validate matches locally against the fetched subset
      const matchedResults: MatchResult[] = extractedInfos.map(info => {
        const attempts = info.candidateCodes;
        let directMatch: ERPRecord | undefined = undefined;
        let matchedAtStage: string | undefined = undefined;

        // Stage 1: Direct Match
        // We check against BOTH StyleCode and CLRCode
        for (const candidate of attempts) {
          const found = erpData.find(d => d.styleCode === candidate || d.clrCode === candidate);
          if (found) {
            directMatch = found;
            matchedAtStage = candidate;
            break; 
          }
        }

        if (directMatch && matchedAtStage) {
          return {
            ...info,
            productCode: matchedAtStage,
            attempts,
            isMatch: true,
            isFuzzy: false,
            erpBrand: directMatch.brand,
            erpStyleCategory: directMatch.styleCategory,
            erpProductName: directMatch.productName,
            status: 'SUCCESS' as const,
            reason: `Direct match: ${matchedAtStage}`
          };
        }

        // Stage 2: Fuzzy Match
        // We create a pool of all valid codes (both styles and CLRs) to fuzzy match against
        const allErpCodes = erpData.flatMap(d => [d.styleCode, d.clrCode]).filter(Boolean);

        let bestFuzzy: { code: string; distance: number; source: string } | null = null;
        for (const candidate of attempts) {
          const fuzzy = findBestFuzzyMatch(candidate, allErpCodes, 2);
          if (fuzzy && (!bestFuzzy || fuzzy.distance < bestFuzzy.distance)) {
            bestFuzzy = { ...fuzzy, source: candidate };
          }
        }

        if (bestFuzzy) {
          // Find the record that owns this fuzzy code
          const fuzzyRecord = erpData.find(d => d.styleCode === bestFuzzy!.code || d.clrCode === bestFuzzy!.code);
          return {
            ...info,
            attempts,
            isMatch: true,
            isFuzzy: true,
            fuzzyMatchCode: bestFuzzy.code,
            erpBrand: fuzzyRecord?.brand,
            erpStyleCategory: fuzzyRecord?.styleCategory,
            erpProductName: fuzzyRecord?.productName,
            status: 'FUZZY' as const,
            reason: `Fuzzy matched "${bestFuzzy.source}" to "${bestFuzzy.code}"`
          };
        }

        // Stage 3: Failure
        return {
          ...info,
          attempts,
          isMatch: false,
          isFuzzy: false,
          status: 'FAILURE' as const,
          reason: `No match found in ERP for: ${attempts.join(', ')}`
        };
      });

      setResults(matchedResults);
      setStatus(FileStatus.COMPLETE);

    } catch (e: any) {
      console.error(e);
      setSyncError("Error querying Databricks: " + e.message);
      setStatus(FileStatus.ERROR);
    }
  }, [token, host, path]);

  const handleFileProcessing = useCallback((files: File[]) => {
    if (files.length === 0) return;

    const csvFile = files.find(f => f.name.toLowerCase().endsWith('.csv'));

    if (csvFile) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const text = e.target?.result as string;
        const listData = parseCSV(text);
        const entries = listData.map(row => ({
          name: row['file name'] || row.filename || row.name || row['product code'] || 'Unknown',
          path: `CSV Upload / ${row.brand || 'No Brand'}`
        }));
        processEntries(entries);
      };
      reader.onerror = () => {
        alert("Failed to read CSV file.");
      };
      reader.readAsText(csvFile);
    } else {
      const entries = files
        .filter(f => f.type.startsWith('image/') || f.name.match(/\.(jpg|jpeg|png|webp|gif)$/i))
        .map(f => ({ name: f.name, path: f.webkitRelativePath || f.name }));

      if (entries.length === 0) {
        alert("No valid image files detected in your selection.");
        return;
      }
      processEntries(entries);
    }
  }, [processEntries]);

  const handleReset = () => {
    setResults([]);
    setSyncError(null);
    setDebugLogs([]);
    setStatus(FileStatus.IDLE);
  };

  const downloadCSV = (data: string, filename: string) => {
    const blob = new Blob([data], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', filename);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const exportDebugLogs = () => {
    const jsonStr = JSON.stringify(debugLogs, null, 2);
    const blob = new Blob([jsonStr], { type: 'application/json' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', 'databricks_debug_logs.json');
    link.click();
  };

  const exportResults = () => {
    const successHeader = "File Name,Status,Extracted Color,Validated Code,ERP Product Name,ERP Category,ERP Brand\n";
    const failureHeader = "File Name,Brand Hint,Attempted Codes,Reason\n";

    const successRows = results
      .filter(r => r.status === 'SUCCESS' || r.status === 'FUZZY')
      .map(r => `"${r.fileName}","${r.status}","${r.colorCode}","${r.isFuzzy ? r.fuzzyMatchCode : r.productCode}","${r.erpProductName || ''}","${r.erpStyleCategory}","${r.erpBrand}"`)
      .join('\n');

    const failureRows = results
      .filter(r => r.status === 'FAILURE')
      .map(r => `"${r.fileName}","${r.brandHint}","${r.attempts.join(' | ')}","${r.reason}"`)
      .join('\n');

    if (successRows) {
      downloadCSV(successHeader + successRows, "validation_success.csv");
    }
    if (failureRows) {
      downloadCSV(failureHeader + failureRows, "validation_failed.csv");
    }
  };

  const stats = {
    total: results.length,
    success: results.filter(r => r.status === 'SUCCESS').length,
    fuzzy: results.filter(r => r.status === 'FUZZY').length,
    failure: results.filter(r => r.status === 'FAILURE').length
  };

  return (
    <div className="min-h-screen bg-slate-50 p-4 md:p-10 font-sans">
      <div className="max-w-7xl mx-auto space-y-8">
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="space-y-1">
            <h1 className="text-3xl font-bold text-slate-900 tracking-tight">ERP Filename Validator</h1>
            <p className="text-slate-500">Auto-query Databricks for Product Code, Name, and Category verification.</p>
          </div>

          <div className="flex flex-wrap items-center gap-3">
            {results.length > 0 && (
              <>
                <button 
                  onClick={handleReset}
                  className="px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-xl font-semibold text-sm hover:bg-slate-50 transition-colors shadow-sm flex items-center gap-2"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                  </svg>
                  Reset All
                </button>
                <button 
                  onClick={exportDebugLogs}
                  className="px-4 py-2 bg-slate-800 text-white rounded-xl font-semibold text-sm hover:bg-slate-900 transition-all shadow-md flex items-center gap-2"
                  title="Download raw SQL request/response logs"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" />
                  </svg>
                  Debug Logs
                </button>
                <button 
                  onClick={exportResults}
                  className="px-4 py-2 bg-indigo-600 text-white rounded-xl font-semibold text-sm hover:bg-indigo-700 transition-all shadow-md flex items-center gap-2"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                  </svg>
                  Export CSVs
                </button>
              </>
            )}
            <div className="flex items-center gap-2 px-3 py-1.5 bg-white border border-slate-200 rounded-xl shadow-sm">
              <div className={`h-2 w-2 rounded-full ${[FileStatus.PARSING, FileStatus.QUERYING, FileStatus.PROCESSING].includes(status) ? 'bg-indigo-500 animate-pulse' : (status === FileStatus.COMPLETE ? 'bg-green-500' : 'bg-slate-300')}`} />
              <span className="text-[10px] font-black text-slate-700 uppercase tracking-widest">
                {status}
              </span>
            </div>
          </div>
        </header>

        <section className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {/* Configuration Panel */}
          <div className={`bg-white p-6 rounded-2xl shadow-sm border transition-all duration-300 ${syncError ? 'border-red-200' : 'border-slate-200'} space-y-4`}>
            <div className="flex items-center justify-between mb-2">
              <div className="flex items-center gap-2">
                <div className="p-2 rounded-lg bg-slate-100 text-slate-600">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                  </svg>
                </div>
                <h2 className="font-bold text-lg text-slate-800">1. Connection Settings</h2>
              </div>
            </div>

            <div className="space-y-3">
              <div className="grid grid-cols-1 gap-3">
                <div className="space-y-1">
                  <label className="text-[10px] uppercase font-bold text-slate-400 tracking-tight ml-1">Access Token</label>
                  <input 
                    type="password"
                    placeholder="dapi..."
                    className="w-full px-3 py-2 text-sm border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                    value={token}
                    onChange={(e) => setToken(e.target.value)}
                  />
                </div>
                <div className="grid grid-cols-2 gap-2">
                  <div className="space-y-1">
                    <label className="text-[10px] uppercase font-bold text-slate-400 tracking-tight ml-1">Server Host</label>
                    <input 
                      type="text"
                      className="w-full px-3 py-2 text-[11px] font-mono border border-slate-200 rounded-lg bg-slate-50"
                      value={host}
                      onChange={(e) => setHost(e.target.value)}
                    />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] uppercase font-bold text-slate-400 tracking-tight ml-1">HTTP Path</label>
                    <input 
                      type="text"
                      className="w-full px-3 py-2 text-[11px] font-mono border border-slate-200 rounded-lg bg-slate-50"
                      value={path}
                      onChange={(e) => setPath(e.target.value)}
                    />
                  </div>
                </div>
              </div>

              {syncError && (
                <div className="p-3 bg-red-50 border border-red-100 rounded-xl flex items-start gap-3 animate-in fade-in slide-in-from-top-1">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-red-500 shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                  <div className="flex flex-col">
                    <p className="text-xs font-bold text-red-700">Config Error</p>
                    <p className="text-[11px] text-red-600 leading-tight">{syncError}</p>
                  </div>
                </div>
              )}

              <div className="text-[11px] text-slate-400 italic bg-slate-50 p-2 rounded border border-slate-100">
                Connection details are used only when you drop files to validate.
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 space-y-4">
            <div className="flex items-center gap-2 mb-2">
              <div className="bg-slate-100 p-2 rounded-lg text-slate-600">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                </svg>
              </div>
              <h2 className="font-bold text-lg text-slate-800">2. Drop Files to Query</h2>
            </div>
            <FileUploadZone 
              label="Upload Images/Folders" 
              onFilesSelected={handleFileProcessing} 
              isFolder={true}
              accept="image/*,.csv"
            />
            {status === FileStatus.QUERYING && (
              <div className="text-center py-2 animate-pulse">
                 <p className="text-xs font-bold text-indigo-600">Querying Databricks for matches...</p>
              </div>
            )}
          </div>
        </section>

        {results.length > 0 && (
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 animate-in fade-in slide-in-from-bottom-2 duration-500">
            {[
              { label: 'Total', value: stats.total, color: 'indigo' },
              { label: 'Success', value: stats.success, color: 'green' },
              { label: 'Fuzzy', value: stats.fuzzy, color: 'orange' },
              { label: 'Fail', value: stats.failure, color: 'red' }
            ].map(stat => (
              <div key={stat.label} className={`bg-white p-4 rounded-xl border-l-4 border-${stat.color}-500 shadow-sm ring-1 ring-slate-200`}>
                <p className="text-slate-500 text-[10px] font-bold uppercase tracking-tight">{stat.label}</p>
                <p className="text-2xl font-black text-slate-800">{stat.value}</p>
              </div>
            ))}
          </div>
        )}

        <main className="space-y-4 pb-20">
          <ResultsTable results={results} />
        </main>
      </div>
    </div>
  );
};

export default App;

export interface ERPRecord {
  productCode: string; // Primary display code (StyleCode)
  styleCode: string;   // Specific Style Code column
  clrCode: string;     // Specific CLR Code column
  brand: string;
  styleCategory: string; // Replaces colorName
  productName: string; 
}

export interface ExtractedInfo {
  fileName: string;
  fullPath: string;
  brandHint: string;
  candidateCodes: string[]; // Progressive fallback variants: [Base, Base-2, Base-2-3]
  productCode: string;      // The primary code found or the best guess from the filename
  colorCode: string;
  tokens: string[];
}

export interface MatchResult extends ExtractedInfo {
  isMatch: boolean;
  isFuzzy: boolean;
  erpBrand?: string;
  erpStyleCategory?: string;
  erpProductName?: string;
  fuzzyMatchCode?: string;
  status: 'SUCCESS' | 'FUZZY' | 'FAILURE';
  attempts: string[]; 
  reason?: string;    
}

export interface QueryLog {
  batchId: number;
  stage: 'KEYS' | 'DETAILS';
  timestamp: string;
  statement: string;
  rawResponse: any;
  parsedCount: number;
  error?: string;
}

export enum FileStatus {
  IDLE = 'IDLE',
  PARSING = 'PARSING',
  QUERYING_KEYS = 'VERIFYING CODES',
  QUERYING_DETAILS = 'FETCHING DATA',
  PROCESSING = 'VALIDATING',
  COMPLETE = 'COMPLETE',
  ERROR = 'ERROR'
}

import React, { useState, useCallback } from 'react';
import FileUploadZone from './components/FileUploadZone';
import ResultsTable from './components/ResultsTable';
import { ERPRecord, MatchResult, FileStatus, ExtractedInfo, QueryLog } from './types';
import { parseFilename, parseCSV } from './utils/parser';
import { findBestFuzzyMatch } from './utils/fuzzy';

// Configuration Defaults
const DEFAULT_DATABRICKS_HOST = "adb-4215830024773554.14.azuredatabricks.net";
const DEFAULT_HTTP_PATH = "b848132ea9c3d9df";

const App: React.FC = () => {
  const [results, setResults] = useState<MatchResult[]>([]);
  const [status, setStatus] = useState<FileStatus>(FileStatus.IDLE);
  const [syncError, setSyncError] = useState<string | null>(null);
  const [debugLogs, setDebugLogs] = useState<QueryLog[]>([]);

  // Configuration State
  const [host, setHost] = useState(DEFAULT_DATABRICKS_HOST);
  const [path, setPath] = useState(DEFAULT_HTTP_PATH);
  const [token, setToken] = useState(""); 

  // Helper to chunk arrays for SQL limits (e.g., IN clause limit)
  const chunkArray = (array: string[], size: number) => {
    const chunked = [];
    for (let i = 0; i < array.length; i += size) {
      chunked.push(array.slice(i, i + size));
    }
    return chunked;
  };

  const PROXY_URL = "https://databricks-proxy-725829572897.europe-west1.run.app"; 

  const executeDatabricksQuery = async (query: string, batchId: number, stage: 'KEYS' | 'DETAILS'): Promise<{ data: any[], log: QueryLog }> => {
    if (!token) throw new Error("Missing Access Token");
    const warehouseId = path.split('/').pop();

    const logEntry: QueryLog = {
      batchId,
      stage,
      timestamp: new Date().toISOString(),
      statement: query,
      rawResponse: null,
      parsedCount: 0
    };

    try {
      const response = await fetch(PROXY_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          host: host,
          warehouseId: warehouseId,
          token: token,
          statement: query
        })
      });

      if (!response.ok) {
        const errorData = await response.json();
        logEntry.error = errorData.message || "HTTP Error";
        logEntry.rawResponse = errorData;
        throw new Error(logEntry.error);
      }

      const result = await response.json();
      logEntry.rawResponse = result;

      if (!result.manifest || !result.result?.data_array) {
        return { data: [], log: logEntry };
      }

      const columns = result.manifest.schema.columns.map((c: any) => c.name.toLowerCase());
      const dataArray = result.result.data_array;

      const parsedData = dataArray.map((row: any[]) => {
        const rowObj: any = {};
        columns.forEach((col: string, idx: number) => {
          rowObj[col] = row[idx];
        });
        return rowObj;
      });

      logEntry.parsedCount = parsedData.length;
      return { data: parsedData, log: logEntry };

    } catch (error: any) {
      console.error(`Query Error [${stage}]`, error);
      logEntry.error = error.message;
      return { data: [], log: logEntry };
    }
  };

  const processEntries = useCallback(async (entries: {name: string, path: string}[]) => {
    if (!token) {
      setSyncError("Please enter your Databricks Access Token to process files.");
      return;
    }

    setSyncError(null);
    setDebugLogs([]); // Clear logs on new run
    setStatus(FileStatus.PARSING);

    // 1. Parse all filenames to get candidates
    const extractedInfos = entries.map(entry => parseFilename(entry.name, entry.path));

    // 2. Collect all unique candidate codes to query
    const allCandidates = new Set<string>();
    extractedInfos.forEach(info => {
      info.candidateCodes.forEach(code => allCandidates.add(code));
    });

    const uniqueCandidatesList = Array.from(allCandidates);

    if (uniqueCandidatesList.length === 0) {
      setSyncError("Could not extract any potential product codes from the filenames.");
      setStatus(FileStatus.IDLE);
      return;
    }

    try {
      // --- STAGE 1: Verify Existence (Fetch Keys Only) ---
      setStatus(FileStatus.QUERYING_KEYS);

      const chunks = chunkArray(uniqueCandidatesList, 200);
      let foundKeys: { styleCode: string; clrCode: string }[] = [];
      let currentLogs: QueryLog[] = [];

      const keyPromises = chunks.map((chunk, index) => {
        const safeCodes = chunk.map(c => c.replace(/'/g, "''").trim()).filter(Boolean);
        if (safeCodes.length === 0) return Promise.resolve(null);

        const codeList = safeCodes.map(c => `'${c}'`).join(',');
        // We fetch both StyleCode and CLRCode to handle matches against either
        const query = `
          SELECT StyleCode, CLRCode
          FROM sportsdirect_sql.dbo.ap21_product
          WHERE StyleCode IN (${codeList}) 
             OR CLRCode IN (${codeList})
        `;
        return executeDatabricksQuery(query, index, 'KEYS');
      });

      const keyResults = await Promise.all(keyPromises);

      keyResults.forEach(res => {
        if (res) {
          const mappedKeys = res.data.map((row: any) => ({
             styleCode: String(row.stylecode || '').toUpperCase().trim(),
             clrCode: String(row.clrcode || '').toUpperCase().trim()
          }));
          foundKeys = [...foundKeys, ...mappedKeys];
          currentLogs.push(res.log);
        }
      });

      // --- STAGE 2: Fetch Full Details for Verified Codes ---
      // Determine which unique StyleCodes we actually need details for
      const verifiedStyleCodes = new Set<string>();

      // Map candidates to found keys to see which StyleCodes are relevant
      // If a candidate matches a CLRCode, we grab its StyleCode.
      uniqueCandidatesList.forEach(candidate => {
        const matches = foundKeys.filter(k => k.styleCode === candidate || k.clrCode === candidate);
        matches.forEach(m => verifiedStyleCodes.add(m.styleCode));
      });

      const styleCodesToFetch = Array.from(verifiedStyleCodes);
      let fetchedRecords: ERPRecord[] = [];

      if (styleCodesToFetch.length > 0) {
        setStatus(FileStatus.QUERYING_DETAILS);

        const detailChunks = chunkArray(styleCodesToFetch, 200);
        const detailPromises = detailChunks.map((chunk, index) => {
          const safeCodes = chunk.map(c => c.replace(/'/g, "''").trim());
          const codeList = safeCodes.map(c => `'${c}'`).join(',');

          const query = `
            SELECT StyleCode, CLRCode, StyleBrand, StyleCategory, Name
            FROM sportsdirect_sql.dbo.ap21_product
            WHERE StyleCode IN (${codeList})
          `;
          // Note: batchId offset by key chunks length to keep IDs unique in log
          return executeDatabricksQuery(query, index + chunks.length, 'DETAILS');
        });

        const detailResults = await Promise.all(detailPromises);

        detailResults.forEach(res => {
          if (res) {
            const records = res.data.map((row: any) => ({
              productCode: String(row.stylecode || '').toUpperCase().trim(),
              styleCode: String(row.stylecode || '').toUpperCase().trim(),
              clrCode: String(row.clrcode || '').toUpperCase().trim(),
              brand: String(row.stylebrand || '').toUpperCase().trim(),
              styleCategory: String(row.stylecategory || '').trim(),
              productName: String(row.name || '').trim()
            }));
            fetchedRecords = [...fetchedRecords, ...records];
            currentLogs.push(res.log);
          }
        });
      }

      setDebugLogs(currentLogs);
      setStatus(FileStatus.PROCESSING);

      // --- STAGE 3: Final Matching ---
      const erpData = fetchedRecords;

      const matchedResults: MatchResult[] = extractedInfos.map(info => {
        const attempts = info.candidateCodes;
        let directMatch: ERPRecord | undefined = undefined;
        let matchedAtStage: string | undefined = undefined;

        // Stage 1: Direct Match
        for (const candidate of attempts) {
          const found = erpData.find(d => d.styleCode === candidate || d.clrCode === candidate);
          if (found) {
            directMatch = found;
            matchedAtStage = candidate;
            break; 
          }
        }

        if (directMatch && matchedAtStage) {
          return {
            ...info,
            productCode: matchedAtStage,
            attempts,
            isMatch: true,
            isFuzzy: false,
            erpBrand: directMatch.brand,
            erpStyleCategory: directMatch.styleCategory,
            erpProductName: directMatch.productName,
            status: 'SUCCESS' as const,
            reason: `Direct match: ${matchedAtStage}`
          };
        }

        // Stage 2: Fuzzy Match
        const allErpCodes = erpData.flatMap(d => [d.styleCode, d.clrCode]).filter(Boolean);

        let bestFuzzy: { code: string; distance: number; source: string } | null = null;
        for (const candidate of attempts) {
          const fuzzy = findBestFuzzyMatch(candidate, allErpCodes, 2);
          if (fuzzy && (!bestFuzzy || fuzzy.distance < bestFuzzy.distance)) {
            bestFuzzy = { ...fuzzy, source: candidate };
          }
        }

        if (bestFuzzy) {
          const fuzzyRecord = erpData.find(d => d.styleCode === bestFuzzy!.code || d.clrCode === bestFuzzy!.code);
          return {
            ...info,
            attempts,
            isMatch: true,
            isFuzzy: true,
            fuzzyMatchCode: bestFuzzy.code,
            erpBrand: fuzzyRecord?.brand,
            erpStyleCategory: fuzzyRecord?.styleCategory,
            erpProductName: fuzzyRecord?.productName,
            status: 'FUZZY' as const,
            reason: `Fuzzy matched "${bestFuzzy.source}" to "${bestFuzzy.code}"`
          };
        }

        // Stage 3: Failure
        return {
          ...info,
          attempts,
          isMatch: false,
          isFuzzy: false,
          status: 'FAILURE' as const,
          reason: `No match found in ERP for: ${attempts.join(', ')}`
        };
      });

      setResults(matchedResults);
      setStatus(FileStatus.COMPLETE);

    } catch (e: any) {
      console.error(e);
      setSyncError("Error querying Databricks: " + e.message);
      setStatus(FileStatus.ERROR);
    }
  }, [token, host, path]);

  const handleFileProcessing = useCallback((files: File[]) => {
    if (files.length === 0) return;

    const csvFile = files.find(f => f.name.toLowerCase().endsWith('.csv'));

    if (csvFile) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const text = e.target?.result as string;
        const listData = parseCSV(text);
        const entries = listData.map(row => ({
          name: row['file name'] || row.filename || row.name || row['product code'] || 'Unknown',
          path: `CSV Upload / ${row.brand || 'No Brand'}`
        }));
        processEntries(entries);
      };
      reader.onerror = () => {
        alert("Failed to read CSV file.");
      };
      reader.readAsText(csvFile);
    } else {
      const entries = files
        .filter(f => f.type.startsWith('image/') || f.name.match(/\.(jpg|jpeg|png|webp|gif)$/i))
        .map(f => ({ name: f.name, path: f.webkitRelativePath || f.name }));

      if (entries.length === 0) {
        alert("No valid image files detected in your selection.");
        return;
      }
      processEntries(entries);
    }
  }, [processEntries]);

  const handleReset = () => {
    setResults([]);
    setSyncError(null);
    setDebugLogs([]);
    setStatus(FileStatus.IDLE);
  };

  const downloadCSV = (data: string, filename: string) => {
    const blob = new Blob([data], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', filename);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const exportDebugLogs = () => {
    const jsonStr = JSON.stringify(debugLogs, null, 2);
    const blob = new Blob([jsonStr], { type: 'application/json' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', 'databricks_debug_logs.json');
    link.click();
  };

  const exportResults = () => {
    const successHeader = "File Name,Status,Extracted Color,Validated Code,ERP Product Name,ERP Category,ERP Brand\n";
    const failureHeader = "File Name,Brand Hint,Attempted Codes,Reason\n";

    const successRows = results
      .filter(r => r.status === 'SUCCESS' || r.status === 'FUZZY')
      .map(r => `"${r.fileName}","${r.status}","${r.colorCode}","${r.isFuzzy ? r.fuzzyMatchCode : r.productCode}","${r.erpProductName || ''}","${r.erpStyleCategory}","${r.erpBrand}"`)
      .join('\n');

    const failureRows = results
      .filter(r => r.status === 'FAILURE')
      .map(r => `"${r.fileName}","${r.brandHint}","${r.attempts.join(' | ')}","${r.reason}"`)
      .join('\n');

    if (successRows) {
      downloadCSV(successHeader + successRows, "validation_success.csv");
    }
    if (failureRows) {
      downloadCSV(failureHeader + failureRows, "validation_failed.csv");
    }
  };

  const stats = {
    total: results.length,
    success: results.filter(r => r.status === 'SUCCESS').length,
    fuzzy: results.filter(r => r.status === 'FUZZY').length,
    failure: results.filter(r => r.status === 'FAILURE').length
  };

  const isWorking = [
    FileStatus.PARSING, 
    FileStatus.QUERYING_KEYS, 
    FileStatus.QUERYING_DETAILS, 
    FileStatus.PROCESSING
  ].includes(status);

  return (
    <div className="min-h-screen bg-slate-50 p-4 md:p-10 font-sans">
      <div className="max-w-7xl mx-auto space-y-8">
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="space-y-1">
            <h1 className="text-3xl font-bold text-slate-900 tracking-tight">ERP Filename Validator</h1>
            <p className="text-slate-500">Auto-query Databricks for Product Code, Name, and Category verification.</p>
          </div>

          <div className="flex flex-wrap items-center gap-3">
            {results.length > 0 && (
              <>
                <button 
                  onClick={handleReset}
                  className="px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-xl font-semibold text-sm hover:bg-slate-50 transition-colors shadow-sm flex items-center gap-2"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                  </svg>
                  Reset All
                </button>
                <button 
                  onClick={exportDebugLogs}
                  className="px-4 py-2 bg-slate-800 text-white rounded-xl font-semibold text-sm hover:bg-slate-900 transition-all shadow-md flex items-center gap-2"
                  title="Download raw SQL request/response logs"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" />
                  </svg>
                  Debug Logs
                </button>
                <button 
                  onClick={exportResults}
                  className="px-4 py-2 bg-indigo-600 text-white rounded-xl font-semibold text-sm hover:bg-indigo-700 transition-all shadow-md flex items-center gap-2"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                  </svg>
                  Export CSVs
                </button>
              </>
            )}
            <div className="flex items-center gap-2 px-3 py-1.5 bg-white border border-slate-200 rounded-xl shadow-sm">
              <div className={`h-2 w-2 rounded-full ${isWorking ? 'bg-indigo-500 animate-pulse' : (status === FileStatus.COMPLETE ? 'bg-green-500' : 'bg-slate-300')}`} />
              <span className="text-[10px] font-black text-slate-700 uppercase tracking-widest">
                {status}
              </span>
            </div>
          </div>
        </header>

        <section className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {/* Configuration Panel */}
          <div className={`bg-white p-6 rounded-2xl shadow-sm border transition-all duration-300 ${syncError ? 'border-red-200' : 'border-slate-200'} space-y-4`}>
            <div className="flex items-center justify-between mb-2">
              <div className="flex items-center gap-2">
                <div className="p-2 rounded-lg bg-slate-100 text-slate-600">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                  </svg>
                </div>
                <h2 className="font-bold text-lg text-slate-800">1. Connection Settings</h2>
              </div>
            </div>

            <div className="space-y-3">
              <div className="grid grid-cols-1 gap-3">
                <div className="space-y-1">
                  <label className="text-[10px] uppercase font-bold text-slate-400 tracking-tight ml-1">Access Token</label>
                  <input 
                    type="password"
                    placeholder="dapi..."
                    className="w-full px-3 py-2 text-sm border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                    value={token}
                    onChange={(e) => setToken(e.target.value)}
                  />
                </div>
                <div className="grid grid-cols-2 gap-2">
                  <div className="space-y-1">
                    <label className="text-[10px] uppercase font-bold text-slate-400 tracking-tight ml-1">Server Host</label>
                    <input 
                      type="text"
                      className="w-full px-3 py-2 text-[11px] font-mono border border-slate-200 rounded-lg bg-slate-50"
                      value={host}
                      onChange={(e) => setHost(e.target.value)}
                    />
                  </div>
                  <div className="space-y-1">
